package com.myllm.financeai.analysis.service;

import org.springframework.stereotype.Service;

@Service
public class QueryIntentService {

    public String classify(String query) {
        if (query.contains("실적")) {
            return "EARNINGS_INTERPRETATION";
        }
        if (query.contains("영향") || query.contains("왜")) {
            return "EVENT_IMPACT_ANALYSIS";
        }
        if (query.contains("비교")) {
            return "COMPANY_COMPARISON";
        }
        return "GENERAL_QA";
    }
}


