3-3. AnalysisSessionService 구현


여기서 실제 저장을 담당한다.


package com.myllm.financeai.analysis.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.myllm.financeai.analysis.dto.AnalysisQueryRequest;
import com.myllm.financeai.analysis.dto.AnalysisResponse;
import com.myllm.financeai.analysis.dto.AnalysisSessionDetailResponse;
import com.myllm.financeai.analysis.dto.AnalysisSessionSummaryResponse;
import com.myllm.financeai.analysis.dto.CitationResponse;
import com.myllm.financeai.analysis.dto.ToolTraceResponse;
import com.myllm.financeai.analysis.entity.AnalysisResult;
import com.myllm.financeai.analysis.entity.AnalysisSession;
import com.myllm.financeai.analysis.enums.AnalysisStatus;
import com.myllm.financeai.analysis.enums.QueryIntentType;
import com.myllm.financeai.analysis.repository.AnalysisResultRepository;
import com.myllm.financeai.analysis.repository.AnalysisSessionRepository;
import com.myllm.financeai.common.exception.BusinessException;
import com.myllm.financeai.common.exception.ErrorCode;
import com.myllm.financeai.common.response.PageResponse;
import com.myllm.financeai.user.entity.User;
import com.myllm.financeai.user.repository.UserRepository;
import java.math.BigDecimal;
import java.util.List;
import java.util.UUID;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional
public class AnalysisSessionService {

    private final UserRepository userRepository;
    private final AnalysisSessionRepository analysisSessionRepository;
    private final AnalysisResultRepository analysisResultRepository;
    private final ObjectMapper objectMapper;

    public UUID save(
            UUID userId,
            AnalysisQueryRequest request,
            QueryIntentType queryIntent,
            AnalysisResponse response
    ) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new BusinessException(ErrorCode.USER_NOT_FOUND));

        AnalysisSession session = AnalysisSession.builder()
                .user(user)
                .title(makeTitle(request.query()))
                .queryText(request.query())
                .queryIntent(queryIntent)
                .status(AnalysisStatus.COMPLETED)
                .requestedTicker(request.ticker())
                .requestedMarket(request.market())
                .timeWindowJson(toJsonSafe(
                        new TimeWindowDto(request.timeFrom(), request.timeTo())
                ))
                .build();

        AnalysisSession savedSession = analysisSessionRepository.save(session);

        AnalysisResult result = AnalysisResult.builder()
                .session(savedSession)
                .finalAnswer(response.answer().fullText())
                .summary(response.answer().summary())
                .confidenceScore(response.answer().confidenceScore())
                .uncertaintyNote(response.answer().uncertaintyNote())
                .citedDocumentIds(toJsonSafe(
                        response.citations().stream()
                                .map(CitationResponse::documentId)
                                .toList()
                ))
                .citedChunkIds("[]")
                .toolTraceJson(toJsonSafe(response.toolTrace()))
                .modelName("mock-model")
                .promptVersion("v1")
                .build();

        analysisResultRepository.save(result);

        return savedSession.getId();
    }

    @Transactional(readOnly = true)
    public PageResponse<AnalysisSessionSummaryResponse> getSessions(UUID userId, Pageable pageable) {
        return PageResponse.from(
                analysisSessionRepository.findByUserIdOrderByCreatedAtDesc(userId, pageable)
                        .map(session -> new AnalysisSessionSummaryResponse(
                                session.getId(),
                                session.getTitle(),
                                session.getQueryText(),
                                session.getQueryIntent().name(),
                                session.getCreatedAt()
                        ))
        );
    }

    @Transactional(readOnly = true)
    public AnalysisSessionDetailResponse getSessionDetail(UUID userId, UUID sessionId) {
        AnalysisSession session = analysisSessionRepository.findById(sessionId)
                .orElseThrow(() -> new BusinessException(ErrorCode.INVALID_INPUT));

        if (!session.getUser().getId().equals(userId)) {
            throw new BusinessException(ErrorCode.FORBIDDEN);
        }

        AnalysisResult result = analysisResultRepository.findBySessionId(sessionId)
                .orElseThrow(() -> new BusinessException(ErrorCode.INVALID_INPUT));

        List<ToolTraceResponse> toolTrace = readToolTrace(result.getToolTraceJson());

        return new AnalysisSessionDetailResponse(
                session.getId(),
                session.getTitle(),
                session.getQueryText(),
                session.getQueryIntent().name(),
                new com.myllm.financeai.analysis.dto.AnalysisAnswerResponse(
                        result.getSummary(),
                        result.getFinalAnswer(),
                        result.getConfidenceScore(),
                        result.getUncertaintyNote()
                ),
                List.of(),
                toolTrace,
                session.getCreatedAt()
        );
    }

    private String makeTitle(String query) {
        if (query == null || query.isBlank()) {
            return "분석 세션";
        }
        return query.length() <= 30 ? query : query.substring(0, 30) + "...";
    }

    private String toJsonSafe(Object value) {
        try {
            return objectMapper.writeValueAsString(value);
        } catch (JsonProcessingException e) {
            return "{}";
        }
    }

    private List<ToolTraceResponse> readToolTrace(String json) {
        try {
            return objectMapper.readerForListOf(ToolTraceResponse.class).readValue(json);
        } catch (Exception e) {
            return List.of();
        }
    }

    private record TimeWindowDto(Object timeFrom, Object timeTo) {
    }
}


포인트는 이거다.


AnalysisResponse를 그대로 받아서 DB 저장

title은 query 앞부분으로 자동 생성

timeWindowJson, toolTraceJson은 JSON 문자열로 저장

나중에 실제 LLM 붙여도 그대로 이어짐



