package com.myllm.financeai.analysis.service;

import com.myllm.financeai.analysis.enums.QueryIntentType;
import org.springframework.stereotype.Service;

@Service
public class QueryIntentService {

    public QueryIntentType classify(String query) {
        if (query.contains("실적")) {
            return QueryIntentType.EARNINGS_INTERPRETATION;
        }
        if (query.contains("영향") || query.contains("왜")) {
            return QueryIntentType.EVENT_IMPACT_ANALYSIS;
        }
        if (query.contains("비교")) {
            return QueryIntentType.COMPANY_COMPARISON;
        }
        if (query.contains("리스크")) {
            return QueryIntentType.RISK_SUMMARY;
        }
        if (query.contains("종목") || query.contains("투자포인트")) {
            return QueryIntentType.STOCK_ANALYSIS;
        }
        return QueryIntentType.GENERAL_QA;
    }
}



