6. Service


여기서는 조회 로직과 기본 검증을 맡긴다.


PriceService.java


package com.myllm.financeai.market.service;

import com.myllm.financeai.common.exception.BusinessException;
import com.myllm.financeai.common.exception.ErrorCode;
import com.myllm.financeai.market.dto.PriceHistoryResponse;
import com.myllm.financeai.market.dto.PriceItemResponse;
import com.myllm.financeai.market.entity.PriceDaily;
import com.myllm.financeai.market.repository.PriceDailyRepository;
import java.time.LocalDate;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class PriceService {

    private final PriceDailyRepository priceDailyRepository;

    public PriceHistoryResponse getPriceHistory(
            String ticker,
            String market,
            LocalDate from,
            LocalDate to
    ) {
        validate(ticker, market, from, to);

        List<PriceDaily> prices = priceDailyRepository
                .findByTickerAndMarketAndTradeDateBetweenOrderByTradeDateAsc(
                        ticker,
                        market,
                        from,
                        to
                );

        List<PriceItemResponse> items = prices.stream()
                .map(price -> new PriceItemResponse(
                        price.getTradeDate(),
                        price.getOpenPrice(),
                        price.getHighPrice(),
                        price.getLowPrice(),
                        price.getClosePrice(),
                        price.getAdjClosePrice(),
                        price.getVolume()
                ))
                .toList();

        return new PriceHistoryResponse(ticker, market, items);
    }

    private void validate(String ticker, String market, LocalDate from, LocalDate to) {
        if (ticker == null || ticker.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (market == null || market.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (from == null || to == null) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (from.isAfter(to)) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
    }
}



