3. Document 엔티티 재확인


기존 Document 엔티티를 그대로 쓰되, 조회/생성에 필요한 메서드를 조금 생각하면서 간다.


Document.java


package com.myllm.financeai.document.entity;

import com.myllm.financeai.common.entity.BaseTimeEntity;
import com.myllm.financeai.document.enums.IngestionStatus;
import com.myllm.financeai.document.enums.SourceType;
import jakarta.persistence.*;
import java.time.LocalDateTime;
import java.util.UUID;
import lombok.AccessLevel;
import lombok.Builder;
import lombok.Getter;
import lombok.NoArgsConstructor;

@Entity
@Table(name = "documents")
@Getter
@NoArgsConstructor(access = AccessLevel.PROTECTED)
public class Document extends BaseTimeEntity {

    @Id
    @GeneratedValue
    private UUID id;

    @Enumerated(EnumType.STRING)
    @Column(name = "source_type", nullable = false, length = 30)
    private SourceType sourceType;

    @Column(name = "source_name", nullable = false, length = 100)
    private String sourceName;

    @Column(name = "external_id", length = 255)
    private String externalId;

    @Column(nullable = false, columnDefinition = "TEXT")
    private String title;

    @Column(columnDefinition = "TEXT")
    private String url;

    @Column(name = "published_at")
    private LocalDateTime publishedAt;

    @Column(nullable = false, length = 10)
    private String language;

    @Lob
    @Column(name = "raw_text")
    private String rawText;

    @Lob
    @Column(name = "cleaned_text", nullable = false)
    private String cleanedText;

    @Lob
    private String summary;

    @Column(name = "document_hash", length = 128)
    private String documentHash;

    @Enumerated(EnumType.STRING)
    @Column(name = "ingestion_status", nullable = false, length = 30)
    private IngestionStatus ingestionStatus;

    @Column(name = "metadata_json", columnDefinition = "jsonb")
    private String metadataJson;

    @Builder
    public Document(
            SourceType sourceType,
            String sourceName,
            String externalId,
            String title,
            String url,
            LocalDateTime publishedAt,
            String language,
            String rawText,
            String cleanedText,
            String summary,
            String documentHash,
            IngestionStatus ingestionStatus,
            String metadataJson
    ) {
        this.sourceType = sourceType;
        this.sourceName = sourceName;
        this.externalId = externalId;
        this.title = title;
        this.url = url;
        this.publishedAt = publishedAt;
        this.language = language;
        this.rawText = rawText;
        this.cleanedText = cleanedText;
        this.summary = summary;
        this.documentHash = documentHash;
        this.ingestionStatus = ingestionStatus;
        this.metadataJson = metadataJson;
    }
}



