5-3. DocumentQueryRepositoryImpl.java


이건 동적 검색이 핵심이다.
1차는 QueryDSL 없이 EntityManager로 구현해도 된다.
포폴에서는 QueryDSL이 더 멋있지만, 지금은 빠르게 가자.


package com.myllm.financeai.document.repository;

import com.myllm.financeai.document.dto.DocumentSearchCondition;
import com.myllm.financeai.document.entity.Document;
import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import jakarta.persistence.TypedQuery;
import java.util.ArrayList;
import java.util.List;
import org.springframework.data.domain.*;
import org.springframework.stereotype.Repository;
import org.springframework.util.StringUtils;

@Repository
public class DocumentQueryRepositoryImpl implements DocumentQueryRepository {

    @PersistenceContext
    private EntityManager em;

    @Override
    public Page<Document> searchDocuments(DocumentSearchCondition condition, Pageable pageable) {
        StringBuilder base = new StringBuilder(" from Document d where 1=1 ");
        List<String> predicates = new ArrayList<>();

        if (StringUtils.hasText(condition.keyword())) {
            predicates.add("""
                (
                    lower(d.title) like lower(concat('%', :keyword, '%'))
                    or lower(d.cleanedText) like lower(concat('%', :keyword, '%'))
                    or lower(coalesce(d.summary, '')) like lower(concat('%', :keyword, '%'))
                )
            """);
        }

        if (condition.sourceType() != null) {
            predicates.add(" d.sourceType = :sourceType ");
        }

        if (condition.publishedFrom() != null) {
            predicates.add(" d.publishedAt >= :publishedFrom ");
        }

        if (condition.publishedTo() != null) {
            predicates.add(" d.publishedAt <= :publishedTo ");
        }

        for (String predicate : predicates) {
            base.append(" and ").append(predicate);
        }

        String contentJpql = "select d " + base + " order by d.publishedAt desc nulls last, d.createdAt desc";
        String countJpql = "select count(d) " + base;

        TypedQuery<Document> contentQuery = em.createQuery(contentJpql, Document.class);
        var countQuery = em.createQuery(countJpql, Long.class);

        if (StringUtils.hasText(condition.keyword())) {
            contentQuery.setParameter("keyword", condition.keyword());
            countQuery.setParameter("keyword", condition.keyword());
        }

        if (condition.sourceType() != null) {
            contentQuery.setParameter("sourceType", condition.sourceType());
            countQuery.setParameter("sourceType", condition.sourceType());
        }

        if (condition.publishedFrom() != null) {
            contentQuery.setParameter("publishedFrom", condition.publishedFrom());
            countQuery.setParameter("publishedFrom", condition.publishedFrom());
        }

        if (condition.publishedTo() != null) {
            contentQuery.setParameter("publishedTo", condition.publishedTo());
            countQuery.setParameter("publishedTo", condition.publishedTo());
        }

        contentQuery.setFirstResult((int) pageable.getOffset());
        contentQuery.setMaxResults(pageable.getPageSize());

        List<Document> content = contentQuery.getResultList();
        Long total = countQuery.getSingleResult();

        return new PageImpl<>(content, pageable, total);
    }
}



6. Service


문서 생성/조회/검색 로직을 담당한다.


DocumentService.java


package com.myllm.financeai.document.service;

import com.myllm.financeai.common.exception.BusinessException;
import com.myllm.financeai.common.exception.ErrorCode;
import com.myllm.financeai.common.response.PageResponse;
import com.myllm.financeai.document.dto.*;
import com.myllm.financeai.document.entity.Document;
import com.myllm.financeai.document.enums.IngestionStatus;
import com.myllm.financeai.document.repository.DocumentRepository;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.time.LocalDateTime;
import java.util.HexFormat;
import java.util.UUID;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.util.StringUtils;

@Service
@RequiredArgsConstructor
@Transactional
public class DocumentService {

    private final DocumentRepository documentRepository;

    public DocumentCreateResponse create(DocumentCreateRequest request) {
        String hash = generateHash(
                request.sourceType().name() + "|" +
                nullSafe(request.sourceName()) + "|" +
                nullSafe(request.title()) + "|" +
                nullSafe(request.cleanedText())
        );

        Document document = Document.builder()
                .sourceType(request.sourceType())
                .sourceName(request.sourceName())
                .externalId(request.externalId())
                .title(request.title())
                .url(request.url())
                .publishedAt(request.publishedAt())
                .language(StringUtils.hasText(request.language()) ? request.language() : "ko")
                .rawText(request.rawText())
                .cleanedText(request.cleanedText())
                .summary(request.summary())
                .documentHash(hash)
                .ingestionStatus(IngestionStatus.PROCESSED)
                .metadataJson(StringUtils.hasText(request.metadataJson()) ? request.metadataJson() : "{}")
                .build();

        Document saved = documentRepository.save(document);

        return new DocumentCreateResponse(
                saved.getId(),
                saved.getTitle(),
                saved.getSourceType().name(),
                saved.getSourceName()
        );
    }

    @Transactional(readOnly = true)
    public PageResponse<DocumentSearchItemResponse> search(
            String keyword,
            String sourceType,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            Pageable pageable
    ) {
        DocumentSearchCondition condition = new DocumentSearchCondition(
                keyword,
                parseSourceType(sourceType),
                publishedFrom,
                publishedTo
        );

        return PageResponse.from(
                documentRepository.searchDocuments(condition, pageable)
                        .map(doc -> new DocumentSearchItemResponse(
                                doc.getId(),
                                doc.getTitle(),
                                doc.getSourceType().name(),
                                doc.getSourceName(),
                                doc.getPublishedAt(),
                                doc.getSummary()
                        ))
        );
    }

    @Transactional(readOnly = true)
    public DocumentDetailResponse getDetail(UUID documentId) {
        Document doc = documentRepository.findById(documentId)
                .orElseThrow(() -> new BusinessException(ErrorCode.DOCUMENT_NOT_FOUND));

        return new DocumentDetailResponse(
                doc.getId(),
                doc.getTitle(),
                doc.getSourceType().name(),
                doc.getSourceName(),
                doc.getExternalId(),
                doc.getUrl(),
                doc.getPublishedAt(),
                doc.getLanguage(),
                doc.getRawText(),
                doc.getCleanedText(),
                doc.getSummary(),
                doc.getMetadataJson(),
                doc.getCreatedAt(),
                doc.getUpdatedAt()
        );
    }

    private com.myllm.financeai.document.enums.SourceType parseSourceType(String sourceType) {
        if (!StringUtils.hasText(sourceType)) {
            return null;
        }
        try {
            return com.myllm.financeai.document.enums.SourceType.valueOf(sourceType.toUpperCase());
        } catch (IllegalArgumentException e) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
    }

    private String generateHash(String input) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hashed = digest.digest(input.getBytes(StandardCharsets.UTF_8));
            return HexFormat.of().formatHex(hashed);
        } catch (Exception e) {
            throw new IllegalStateException("문서 해시 생성에 실패했습니다.");
        }
    }

    private String nullSafe(String value) {
        return value == null ? "" : value;
    }
}



