DocumentController.java


package com.myllm.financeai.document.controller;

import com.myllm.financeai.common.response.ApiResponse;
import com.myllm.financeai.common.response.PageResponse;
import com.myllm.financeai.document.dto.DocumentCreateRequest;
import com.myllm.financeai.document.dto.DocumentCreateResponse;
import com.myllm.financeai.document.dto.DocumentDetailResponse;
import com.myllm.financeai.document.dto.DocumentSearchItemResponse;
import com.myllm.financeai.document.service.DocumentService;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.security.SecurityRequirement;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import java.time.LocalDateTime;
import java.util.UUID;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Pageable;
import org.springframework.data.web.PageableDefault;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.web.bind.annotation.*;

@Tag(name = "Documents", description = "문서 저장 / 검색 / 조회 API")
@RestController
@RequestMapping("/api/v1/documents")
@RequiredArgsConstructor
public class DocumentController {

    private final DocumentService documentService;

    @Operation(summary = "문서 저장", security = @SecurityRequirement(name = "bearerAuth"))
    @PostMapping
    public ApiResponse<DocumentCreateResponse> create(
            @RequestBody @Valid DocumentCreateRequest request
    ) {
        return ApiResponse.success(documentService.create(request), "문서가 저장되었습니다.");
    }

    @Operation(summary = "문서 검색")
    @GetMapping("/search")
    public ApiResponse<PageResponse<DocumentSearchItemResponse>> search(
            @RequestParam(required = false) String q,
            @RequestParam(required = false) String sourceType,
            @RequestParam(required = false)
            @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME)
            LocalDateTime publishedFrom,
            @RequestParam(required = false)
            @DateTimeFormat(iso = DateTimeFormat.ISO.DATE_TIME)
            LocalDateTime publishedTo,
            @PageableDefault(size = 20) Pageable pageable
    ) {
        return ApiResponse.success(
                documentService.search(q, sourceType, publishedFrom, publishedTo, pageable)
        );
    }

    @Operation(summary = "문서 상세 조회")
    @GetMapping("/{documentId}")
    public ApiResponse<DocumentDetailResponse> getDetail(@PathVariable UUID documentId) {
        return ApiResponse.success(documentService.getDetail(documentId));
    }
}



9. SecurityConfig 조정


문서 검색/상세는 공개, 문서 저장은 인증 필요로 가면 좋다.
이미 GET /api/v1/documents/** 공개했으면 그대로 유지하면 된다.


대충 이 상태면 충분하다.


.requestMatchers(HttpMethod.GET, "/api/v1/documents/**").permitAll()


문서 저장 POST /api/v1/documents는 인증 필요 상태로 남는다.



10. Flyway V4 추천


문서 테이블 자체는 이미 있으니, 이번 단계에서 꼭 필요한 DB 변경은 사실 없어도 된다.
하지만 중복 저장 방지나 검색 최적화를 고려하면 V4에서 인덱스 보강 정도는 해둘 수 있다.


파일명:


V4__document_indexes.sql


V4__document_indexes.sql


create index if not exists idx_documents_title
    on documents using gin (to_tsvector('simple', coalesce(title, '')));

create index if not exists idx_documents_cleaned_text
    on documents using gin (to_tsvector('simple', coalesce(cleaned_text, '')));

create index if not exists idx_documents_summary
    on documents using gin (to_tsvector('simple', coalesce(summary, '')));


주의할 점이 있다.


지금 DocumentQueryRepositoryImpl은 like 기반이라 이 GIN 인덱스를 아직 직접 쓰진 않는다.
그래도 나중에 PostgreSQL full-text search로 넘어갈 때 기반이 된다.


즉 지금 당장 필수는 아님.
정리하면:


바로 실행만 원함 → V4 생략 가능

검색 확장성까지 잡고 싶음 → V4 추가


내 추천은 넣어두는 것이다.



