package com.myllm.financeai.market.service;

import com.myllm.financeai.analysis.dto.PriceSummary;
import com.myllm.financeai.common.exception.BusinessException;
import com.myllm.financeai.common.exception.ErrorCode;
import com.myllm.financeai.market.dto.PriceHistoryResponse;
import com.myllm.financeai.market.dto.PriceItemResponse;
import com.myllm.financeai.market.entity.PriceDaily;
import com.myllm.financeai.market.repository.PriceDailyRepository;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class PriceService {

    private final PriceDailyRepository priceDailyRepository;

    public PriceHistoryResponse getPriceHistory(
            String ticker,
            String market,
            LocalDate from,
            LocalDate to
    ) {
        validate(ticker, market, from, to);

        List<PriceDaily> prices = priceDailyRepository
                .findByTickerAndMarketAndTradeDateBetweenOrderByTradeDateAsc(
                        ticker,
                        market,
                        from,
                        to
                );

        List<PriceItemResponse> items = prices.stream()
                .map(price -> new PriceItemResponse(
                        price.getTradeDate(),
                        price.getOpenPrice(),
                        price.getHighPrice(),
                        price.getLowPrice(),
                        price.getClosePrice(),
                        price.getAdjClosePrice(),
                        price.getVolume()
                ))
                .toList();

        return new PriceHistoryResponse(ticker, market, items);
    }

    public PriceSummary summarizePriceHistory(
            String ticker,
            String market,
            LocalDate from,
            LocalDate to
    ) {
        validate(ticker, market, from, to);

        List<PriceDaily> prices = priceDailyRepository
                .findByTickerAndMarketAndTradeDateBetweenOrderByTradeDateAsc(
                        ticker,
                        market,
                        from,
                        to
                );

        if (prices.isEmpty()) {
            return null;
        }

        PriceDaily first = prices.get(0);
        PriceDaily last = prices.get(prices.size() - 1);

        BigDecimal firstClose = first.getClosePrice();
        BigDecimal lastClose = last.getClosePrice();
        BigDecimal absoluteChange = lastClose.subtract(firstClose);

        BigDecimal percentChange = BigDecimal.ZERO;
        if (firstClose.compareTo(BigDecimal.ZERO) != 0) {
            percentChange = absoluteChange
                    .divide(firstClose, 6, RoundingMode.HALF_UP)
                    .multiply(BigDecimal.valueOf(100))
                    .setScale(2, RoundingMode.HALF_UP);
        }

        long averageVolume = Math.round(
                prices.stream()
                        .mapToLong(PriceDaily::getVolume)
                        .average()
                        .orElse(0)
        );

        return new PriceSummary(
                ticker,
                market,
                first.getTradeDate(),
                last.getTradeDate(),
                firstClose,
                lastClose,
                absoluteChange,
                percentChange,
                averageVolume,
                prices.size()
        );
    }

    private void validate(String ticker, String market, LocalDate from, LocalDate to) {
        if (ticker == null || ticker.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (market == null || market.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (from == null || to == null) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (from.isAfter(to)) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
    }
}



