@Transactional(readOnly = true)
public java.util.List<DocumentSearchItemResponse> searchTopDocumentsForAnalysis(
        String keyword,
        String sourceType,
        java.time.LocalDateTime publishedFrom,
        java.time.LocalDateTime publishedTo,
        int limit
) {
    org.springframework.data.domain.Pageable pageable =
