    DocumentSearchCondition condition = new DocumentSearchCondition(
            keyword,
            parseSourceType(sourceType),
            publishedFrom,
            publishedTo
    );

    return documentRepository.searchDocuments(condition, pageable)
            .stream()
            .map(doc -> new DocumentSearchItemResponse(
                    doc.getId(),
                    doc.getTitle(),
                    doc.getSourceType().name(),
                    doc.getSourceName(),
                    doc.getPublishedAt(),
                    doc.getSummary()
            ))
            .toList();
}



