import com.myllm.financeai.market.service.PriceService;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class AnalysisPipelineService {

    private final DocumentService documentService;
    private final PriceService priceService;

    public AnalysisMaterial loadMaterial(
            String query,
            QueryIntentType intent,
            String ticker,
            String market,
            LocalDateTime timeFrom,
            LocalDateTime timeTo
    ) {
        List<DocumentSearchItemResponse> documents =
                documentService.searchTopDocumentsForAnalysis(
                        query,
                        "NEWS",
                        timeFrom,
                        timeTo,
                        5
                );

        PriceSummary priceSummary = null;
        if (ticker != null && !ticker.isBlank() && market != null && !market.isBlank()
                && timeFrom != null && timeTo != null) {
            priceSummary = priceService.summarizePriceHistory(
                    ticker,
                    market,
                    timeFrom.toLocalDate(),
                    timeTo.toLocalDate()
            );
        }

        return new AnalysisMaterial(documents, priceSummary);
    }
}


