package com.myllm.financeai.analysis.service;

import com.myllm.financeai.analysis.dto.AnalysisMaterial;
import com.myllm.financeai.analysis.dto.AnalysisQueryRequest;
import com.myllm.financeai.analysis.dto.AnalysisResponse;
import com.myllm.financeai.analysis.dto.AnalysisSessionDetailResponse;
import com.myllm.financeai.analysis.dto.AnalysisSessionSummaryResponse;
import com.myllm.financeai.analysis.enums.QueryIntentType;
import com.myllm.financeai.common.response.PageResponse;
import java.util.UUID;
import lombok.RequiredArgsConstructor;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional
public class AnalysisService {

    private final QueryIntentService queryIntentService;
    private final AnalysisPipelineService analysisPipelineService;
    private final AnalysisSessionService analysisSessionService;
    private final AnswerComposerService answerComposerService;

    public AnalysisResponse analyze(UUID userId, AnalysisQueryRequest request) {
        QueryIntentType intent = queryIntentService.classify(request.query());

        AnalysisMaterial material = analysisPipelineService.loadMaterial(
                request.query(),
                intent,
                request.ticker(),
                request.market(),
                request.timeFrom(),
                request.timeTo()
        );

        AnalysisResponse response = answerComposerService.compose(
                request.query(),
                intent.name(),
                material
        );

        UUID sessionId = analysisSessionService.save(userId, request, intent, response);

        return answerComposerService.withSessionId(response, sessionId);
    }

    @Transactional(readOnly = true)
    public PageResponse<AnalysisSessionSummaryResponse> getSessions(
            UUID userId,
            Pageable pageable
    ) {
        return analysisSessionService.getSessions(userId, pageable);
    }

    @Transactional(readOnly = true)
    public AnalysisSessionDetailResponse getSessionDetail(
            UUID userId,
            UUID sessionId
    ) {
        return analysisSessionService.getSessionDetail(userId, sessionId);
    }
}



9. AnalysisQueryRequest 사용 팁


이제 이 구조에서는 ticker, market, timeFrom, timeTo를 넣는 게 중요해진다.


예시 요청:


