6. FinancialMetricService


FinancialMetricService.java


package com.myllm.financeai.market.service;

import com.myllm.financeai.common.exception.BusinessException;
import com.myllm.financeai.common.exception.ErrorCode;
import com.myllm.financeai.market.dto.FinancialMetricItemResponse;
import com.myllm.financeai.market.dto.FinancialMetricResponse;
import com.myllm.financeai.market.dto.FinancialSummary;
import com.myllm.financeai.market.entity.FinancialMetric;
import com.myllm.financeai.market.repository.FinancialMetricRepository;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class FinancialMetricService {

    private final FinancialMetricRepository financialMetricRepository;

    public FinancialMetricResponse getFinancialMetrics(
            String ticker,
            String market,
            String periodType
    ) {
        validate(ticker, market);

        List<FinancialMetric> metrics;
        if (periodType == null || periodType.isBlank()) {
            metrics = financialMetricRepository.findByTickerAndMarketOrderByFiscalYearDescFiscalQuarterDesc(
                    ticker, market
            );
        } else {
            metrics = financialMetricRepository.findByTickerAndMarketAndPeriodTypeOrderByFiscalYearDescFiscalQuarterDesc(
                    ticker, market, periodType
            );
        }

        List<FinancialMetricItemResponse> items = metrics.stream()
                .map(metric -> new FinancialMetricItemResponse(
                        metric.getFiscalYear(),
                        metric.getFiscalQuarter(),
                        metric.getPeriodType(),
                        metric.getRevenue(),
                        metric.getOperatingIncome(),
                        metric.getNetIncome(),
                        metric.getEps(),
                        metric.getOperatingMargin(),
                        metric.getNetMargin(),
                        metric.getDebtRatio(),
                        metric.getSourceName()
                ))
                .toList();

        return new FinancialMetricResponse(ticker, market, items);
    }

    public FinancialSummary summarizeLatestFinancials(String ticker, String market) {
        validate(ticker, market);

        return financialMetricRepository.findTopByTickerAndMarketOrderByFiscalYearDescFiscalQuarterDesc(
                        ticker, market
                )
                .map(metric -> new FinancialSummary(
                        metric.getTicker(),
                        metric.getMarket(),
                        metric.getFiscalYear(),
                        metric.getFiscalQuarter(),
                        metric.getPeriodType(),
                        metric.getRevenue(),
                        metric.getOperatingIncome(),
                        metric.getNetIncome(),
                        metric.getEps(),
                        metric.getOperatingMargin(),
                        metric.getNetMargin(),
                        metric.getDebtRatio()
                ))
                .orElse(null);
    }

    private void validate(String ticker, String market) {
        if (ticker == null || ticker.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
        if (market == null || market.isBlank()) {
            throw new BusinessException(ErrorCode.INVALID_INPUT);
        }
    }
}



