package com.myllm.financeai.analysis.service;

import com.myllm.financeai.analysis.dto.AnalysisMaterial;
import com.myllm.financeai.analysis.dto.PriceSummary;
import com.myllm.financeai.analysis.enums.QueryIntentType;
import com.myllm.financeai.document.dto.DocumentSearchItemResponse;
import com.myllm.financeai.document.service.DocumentService;
import com.myllm.financeai.market.dto.FinancialSummary;
import com.myllm.financeai.market.service.FinancialMetricService;
import com.myllm.financeai.market.service.PriceService;
import java.time.LocalDateTime;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class AnalysisPipelineService {

    private final DocumentService documentService;
    private final PriceService priceService;
    private final FinancialMetricService financialMetricService;

    public AnalysisMaterial loadMaterial(
            String query,
            QueryIntentType intent,
            String ticker,
            String market,
            LocalDateTime timeFrom,
            LocalDateTime timeTo
    ) {
        List<DocumentSearchItemResponse> documents =
                documentService.searchTopDocumentsForAnalysis(
                        query,
                        "NEWS",
                        timeFrom,
                        timeTo,
                        5
                );

        PriceSummary priceSummary = null;
        FinancialSummary financialSummary = null;

        if (ticker != null && !ticker.isBlank() && market != null && !market.isBlank()) {
            if (timeFrom != null && timeTo != null) {
                priceSummary = priceService.summarizePriceHistory(
                        ticker,
                        market,
                        timeFrom.toLocalDate(),
                        timeTo.toLocalDate()
                );
            }

            financialSummary = financialMetricService.summarizeLatestFinancials(ticker, market);
        }

        return new AnalysisMaterial(documents, priceSummary, financialSummary);
    }
}



10. AnswerComposerService에 재무 요약 반영


이제 분석문에 재무를 넣는다.


AnswerComposerService.java 수정본


package com.myllm.financeai.analysis.service;

import com.myllm.financeai.analysis.dto.*;
import com.myllm.financeai.document.dto.DocumentSearchItemResponse;
import com.myllm.financeai.market.dto.FinancialSummary;
import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;

@Service
public class AnswerComposerService {

    public AnalysisResponse compose(
            String query,
            String intent,
            AnalysisMaterial material
    ) {
        String summary = buildSummary(material);
        String fullText = buildFullText(query, intent, material);
        BigDecimal confidence = estimateConfidence(material);
        String uncertaintyNote = buildUncertainty(material);

        List<CitationResponse> citations = material.documents().stream()
                .map(doc -> new CitationResponse(
                        doc.documentId(),
                        doc.title(),
                        doc.sourceName(),
                        doc.publishedAt(),
                        null
                ))
                .toList();

        List<RelatedEntityResponse> relatedEntities = new ArrayList<>();
        if (material.priceSummary() != null) {
            relatedEntities.add(new RelatedEntityResponse("TICKER", material.priceSummary().ticker()));
            relatedEntities.add(new RelatedEntityResponse("MARKET", material.priceSummary().market()));
        }

        return new AnalysisResponse(
                null,
                intent,
                new AnalysisAnswerResponse(
                        summary,
                        fullText,
                        confidence,
                        uncertaintyNote
                ),
                citations,
                relatedEntities,
                List.of(
                        new ToolTraceResponse("documentSearch", "SUCCESS"),
                        new ToolTraceResponse(
                                "priceSummary",
                                material.priceSummary() != null ? "SUCCESS" : "SKIPPED"
                        ),
                        new ToolTraceResponse(
                                "financialSummary",
                                material.financialSummary() != null ? "SUCCESS" : "SKIPPED"
                        )
                )
        );
    }

    public AnalysisResponse withSessionId(AnalysisResponse response, UUID sessionId) {
        return new AnalysisResponse(
                sessionId,
                response.queryIntent(),
                response.answer(),
                response.citations(),
                response.relatedEntities(),
                response.toolTrace()
        );
    }

    private String buildSummary(AnalysisMaterial material) {
        boolean hasDocs = !material.documents().isEmpty();
        boolean hasPrice = material.priceSummary() != null;
        boolean hasFinancial = material.financialSummary() != null;

        if (hasDocs && hasPrice && hasFinancial) {
            BigDecimal pct = material.priceSummary().percentChange();
            String direction = pct.compareTo(BigDecimal.ZERO) >= 0 ? "상승" : "하락";
            return "문서, 가격, 재무 데이터를 함께 보면 최근 이슈와 주가 흐름, 최신 재무 상태를 함께 연결한 1차 분석이 가능합니다. 해당 구간 주가는 "
                    + direction + " 흐름(" + pct + "%)을 보였습니다.";
        }

        if (hasPrice && hasFinancial) {
            return "가격과 재무 데이터를 기반으로 기초 분석을 수행했습니다.";
        }

        if (hasDocs && hasPrice) {
            return "문서와 가격 데이터를 결합한 1차 이슈 분석을 수행했습니다.";
        }

        if (hasFinancial) {
            return "최신 재무 데이터 중심의 기초 분석을 수행했습니다.";
        }

        return "현재 연결된 분석 데이터가 제한적입니다.";
    }

    private String buildFullText(String query, String intent, AnalysisMaterial material) {
        StringBuilder sb = new StringBuilder();

        sb.append("질문: ").append(query).append("\n\n");
        sb.append("분석 유형: ").append(intent).append("\n\n");

        if (material.priceSummary() != null) {
            PriceSummary p = material.priceSummary();
            sb.append("[가격 흐름]\n");
            sb.append("- 기간: ").append(p.fromDate()).append(" ~ ").append(p.toDate()).append("\n");
            sb.append("- 시작 종가: ").append(p.firstClosePrice()).append("\n");
            sb.append("- 마지막 종가: ").append(p.lastClosePrice()).append("\n");
            sb.append("- 절대 변화: ").append(p.absoluteChange()).append("\n");
            sb.append("- 등락률: ").append(p.percentChange()).append("%\n");
            sb.append("- 평균 거래량: ").append(p.averageVolume()).append("\n\n");
        }

        if (material.financialSummary() != null) {
            FinancialSummary f = material.financialSummary();
            sb.append("[최신 재무 요약]\n");
            sb.append("- 기준 기간: ").append(f.latestFiscalYear());
            if (f.latestFiscalQuarter() != null) {
                sb.append(" Q").append(f.latestFiscalQuarter());
            }
            sb.append(" / ").append(f.periodType()).append("\n");
            sb.append("- 매출: ").append(f.revenue()).append("\n");
            sb.append("- 영업이익: ").append(f.operatingIncome()).append("\n");
            sb.append("- 순이익: ").append(f.netIncome()).append("\n");
            sb.append("- EPS: ").append(f.eps()).append("\n");
            sb.append("- 영업이익률: ").append(f.operatingMargin()).append("\n");
            sb.append("- 순이익률: ").append(f.netMargin()).append("\n");
            sb.append("- 부채비율: ").append(f.debtRatio()).append("\n\n");
        }

        if (!material.documents().isEmpty()) {
            sb.append("[관련 문서 요약]\n");
            int idx = 1;
            for (DocumentSearchItemResponse doc : material.documents()) {
                sb.append(idx++)
                        .append(". ")
                        .append(doc.title())
                        .append(" / ")
                        .append(doc.sourceName());

                if (doc.publishedAt() != null) {
                    sb.append(" / ").append(doc.publishedAt());
                }
                sb.append("\n");

                if (doc.summary() != null && !doc.summary().isBlank()) {
                    sb.append("   - ").append(doc.summary()).append("\n");
                }
            }
            sb.append("\n");
        }

        sb.append("[1차 해석]\n");

        if (material.priceSummary() != null) {
            BigDecimal pct = material.priceSummary().percentChange();
            if (pct.compareTo(BigDecimal.ZERO) > 0) {
                sb.append("- 최근 주가 흐름은 상승 방향입니다.\n");
            } else if (pct.compareTo(BigDecimal.ZERO) < 0) {
                sb.append("- 최근 주가 흐름은 하락 방향입니다.\n");
            } else {
                sb.append("- 최근 주가 흐름은 제한적입니다.\n");
            }
        }

        if (material.financialSummary() != null) {
            FinancialSummary f = material.financialSummary();

            if (f.operatingMargin() != null) {
                if (f.operatingMargin().compareTo(BigDecimal.valueOf(15)) >= 0) {
                    sb.append("- 영업이익률이 상대적으로 높은 편이라 수익성 측면은 양호하게 볼 수 있습니다.\n");
                } else if (f.operatingMargin().compareTo(BigDecimal.valueOf(5)) < 0) {
                    sb.append("- 영업이익률이 낮은 편이라 수익성 방어 여부를 더 확인할 필요가 있습니다.\n");
                } else {
                    sb.append("- 영업이익률은 중간 수준으로 해석할 수 있습니다.\n");
                }
            }

            if (f.debtRatio() != null) {
                if (f.debtRatio().compareTo(BigDecimal.valueOf(200)) >= 0) {
                    sb.append("- 부채비율이 높은 편이라 재무 안정성 측면 점검이 필요합니다.\n");
                } else {
                    sb.append("- 부채비율은 과도하게 높지 않은 수준으로 보입니다.\n");
                }
            }
        }

        if (!material.documents().isEmpty()) {
            sb.append("- 최근 문서 흐름을 함께 보면 뉴스/이슈와 시장 반응을 연결해서 해석할 수 있습니다.\n");
        }

        sb.append("- 현재 단계는 문서, 가격, 최신 재무를 결합한 1차 분석이며, 향후 실적 추이 비교·수급·밸류에이션까지 붙이면 분석 품질이 더 올라갑니다.\n");

        return sb.toString();
    }

    private BigDecimal estimateConfidence(AnalysisMaterial material) {
        int score = 0;

        if (material.priceSummary() != null) score++;
        if (material.financialSummary() != null) score++;
        if (material.documents() != null && !material.documents().isEmpty()) score++;

        return switch (score) {
            case 3 -> new BigDecimal("0.84");
            case 2 -> new BigDecimal("0.70");
            case 1 -> new BigDecimal("0.52");
            default -> new BigDecimal("0.30");
        };
    }

    private String buildUncertainty(AnalysisMaterial material) {
        boolean hasDocs = !material.documents().isEmpty();
        boolean hasPrice = material.priceSummary() != null;
        boolean hasFinancial = material.financialSummary() != null;

        if (hasDocs && hasPrice && hasFinancial) {
            return "현재 분석은 최근 문서, 가격 흐름, 최신 재무 요약을 결합한 1차 해석이며, 재무 추세 비교와 컨센서스 대비 평가는 아직 반영되지 않았습니다.";
        }
        if (hasFinancial && !hasDocs) {
            return "재무 데이터만으로는 최근 시장 심리와 이슈 반응을 충분히 설명하기 어렵습니다.";
        }
        if (hasPrice && !hasFinancial) {
            return "가격 변동만으로는 기업의 펀더멘털까지 판단하기 어렵습니다.";
        }
        return "분석 근거가 충분하지 않습니다.";
    }
}



