package com.myllm.financeai.ai.service;

import com.myllm.financeai.ai.dto.FinanceAnalysisAiResult;
import com.myllm.financeai.analysis.dto.AnalysisMaterial;
import com.myllm.financeai.analysis.dto.PriceSummary;
import com.myllm.financeai.document.dto.DocumentSearchItemResponse;
import com.myllm.financeai.market.dto.FinancialSummary;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.ai.chat.client.ChatClient;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class FinanceAnalysisAiService {

    private final ChatClient.Builder chatClientBuilder;

    public FinanceAnalysisAiResult generate(
            String query,
            String intent,
            AnalysisMaterial material
    ) {
        ChatClient chatClient = chatClientBuilder.build();

        String systemPrompt = """
                너는 금융 분석 보조 AI다.
                역할은 투자 권유가 아니라, 주어진 문서/가격/재무 데이터를 바탕으로 근거 기반 1차 분석을 수행하는 것이다.

                반드시 지켜라:
                1. 제공된 데이터 범위 안에서만 말할 것
                2. 모르면 모른다고 말할 것
                3. 추정과 사실을 구분할 것
                4. 답변은 아래 3개 섹션으로 나눌 것
                   [SUMMARY]
                   ...
                   [FULL_TEXT]
                   ...
                   [UNCERTAINTY]
                   ...
                5. 과장된 표현, 투자 권유 표현 금지
                """;

        String userPrompt = buildUserPrompt(query, intent, material);

        String raw = chatClient.prompt()
                .system(systemPrompt)
                .user(userPrompt)
                .call()
                .content();

        return parse(raw);
    }

    private String buildUserPrompt(String query, String intent, AnalysisMaterial material) {
        StringBuilder sb = new StringBuilder();

        sb.append("질문: ").append(query).append("\n");
        sb.append("분석유형: ").append(intent).append("\n\n");

        if (material.priceSummary() != null) {
            PriceSummary p = material.priceSummary();
            sb.append("[가격 데이터]\n");
            sb.append("- ticker: ").append(p.ticker()).append("\n");
            sb.append("- market: ").append(p.market()).append("\n");
            sb.append("- 기간: ").append(p.fromDate()).append(" ~ ").append(p.toDate()).append("\n");
            sb.append("- 시작 종가: ").append(p.firstClosePrice()).append("\n");
            sb.append("- 마지막 종가: ").append(p.lastClosePrice()).append("\n");
            sb.append("- 절대 변화: ").append(p.absoluteChange()).append("\n");
            sb.append("- 등락률: ").append(p.percentChange()).append("%\n");
            sb.append("- 평균 거래량: ").append(p.averageVolume()).append("\n\n");
        }

        if (material.financialSummary() != null) {
            FinancialSummary f = material.financialSummary();
            sb.append("[최신 재무 데이터]\n");
            sb.append("- 기준연도: ").append(f.latestFiscalYear()).append("\n");
            sb.append("- 기준분기: ").append(f.latestFiscalQuarter()).append("\n");
            sb.append("- periodType: ").append(f.periodType()).append("\n");
            sb.append("- 매출: ").append(f.revenue()).append("\n");
            sb.append("- 영업이익: ").append(f.operatingIncome()).append("\n");
            sb.append("- 순이익: ").append(f.netIncome()).append("\n");
            sb.append("- EPS: ").append(f.eps()).append("\n");
            sb.append("- 영업이익률: ").append(f.operatingMargin()).append("\n");
            sb.append("- 순이익률: ").append(f.netMargin()).append("\n");
            sb.append("- 부채비율: ").append(f.debtRatio()).append("\n\n");
        }

        List<DocumentSearchItemResponse> docs = material.documents();
        if (docs != null && !docs.isEmpty()) {
            sb.append("[관련 문서]\n");
            int i = 1;
            for (DocumentSearchItemResponse doc : docs) {
                sb.append(i++).append(". ")
                        .append(doc.title())
                        .append(" / ")
                        .append(doc.sourceName())
                        .append(" / ")
                        .append(doc.publishedAt())
                        .append("\n");
                if (doc.summary() != null && !doc.summary().isBlank()) {
                    sb.append("   - ").append(doc.summary()).append("\n");
                }
            }
            sb.append("\n");
        }

        sb.append("""
                위 자료만 바탕으로 1차 분석을 작성하라.
                형식:
                [SUMMARY]
                한두 문장 요약

                [FULL_TEXT]
                3~6문장 분석

                [UNCERTAINTY]
                불확실성 한두 문장
                """);

        return sb.toString();
    }

    private FinanceAnalysisAiResult parse(String raw) {
        String summary = extractSection(raw, "[SUMMARY]", "[FULL_TEXT]");
        String fullText = extractSection(raw, "[FULL_TEXT]", "[UNCERTAINTY]");
        String uncertainty = extractSection(raw, "[UNCERTAINTY]", null);

        return new FinanceAnalysisAiResult(
                emptyToFallback(summary, "요약을 생성하지 못했습니다."),
                emptyToFallback(fullText, raw),
                emptyToFallback(uncertainty, "현재 데이터 범위에 기반한 제한적 분석입니다.")
        );
    }

    private String extractSection(String raw, String start, String end) {
        int startIdx = raw.indexOf(start);
        if (startIdx < 0) return "";

        int contentStart = startIdx + start.length();
        int endIdx = end == null ? raw.length() : raw.indexOf(end, contentStart);

        if (endIdx < 0) endIdx = raw.length();
        return raw.substring(contentStart, endIdx).trim();
    }

    private String emptyToFallback(String value, String fallback) {
        return (value == null || value.isBlank()) ? fallback : value;
    }
}


그 다음 AnswerComposerService는 규칙 기반 문장 생성 대신, AI 결과를 받아 DTO로 조립하게 바꾼다.


package com.myllm.financeai.analysis.service;

import com.myllm.financeai.ai.dto.FinanceAnalysisAiResult;
import com.myllm.financeai.analysis.dto.*;
import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;

@Service
public class AnswerComposerService {

    public AnalysisResponse composeWithAi(
            String intent,
            AnalysisMaterial material,
            FinanceAnalysisAiResult aiResult
    ) {
        List<CitationResponse> citations = material.documents().stream()
                .map(doc -> new CitationResponse(
                        doc.documentId(),
                        doc.title(),
                        doc.sourceName(),
                        doc.publishedAt(),
                        null
                ))
                .toList();

        List<RelatedEntityResponse> relatedEntities = new ArrayList<>();
        if (material.priceSummary() != null) {
            relatedEntities.add(new RelatedEntityResponse("TICKER", material.priceSummary().ticker()));
            relatedEntities.add(new RelatedEntityResponse("MARKET", material.priceSummary().market()));
        }

        return new AnalysisResponse(
                null,
                intent,
                new AnalysisAnswerResponse(
                        aiResult.summary(),
                        aiResult.fullText(),
                        estimateConfidence(material),
                        aiResult.uncertaintyNote()
                ),
                citations,
                relatedEntities,
                List.of(
                        new ToolTraceResponse("documentSearch", "SUCCESS"),
                        new ToolTraceResponse(
                                "priceSummary",
                                material.priceSummary() != null ? "SUCCESS" : "SKIPPED"
                        ),
                        new ToolTraceResponse(
                                "financialSummary",
                                material.financialSummary() != null ? "SUCCESS" : "SKIPPED"
                        ),
                        new ToolTraceResponse("springAiChatClient", "SUCCESS")
                )
        );
    }

    public AnalysisResponse withSessionId(AnalysisResponse response, UUID sessionId) {
        return new AnalysisResponse(
                sessionId,
                response.queryIntent(),
                response.answer(),
                response.citations(),
                response.relatedEntities(),
                response.toolTrace()
        );
    }

    private BigDecimal estimateConfidence(AnalysisMaterial material) {
        int score = 0;
        if (material.priceSummary() != null) score++;
        if (material.financialSummary() != null) score++;
        if (material.documents() != null && !material.documents().isEmpty()) score++;

        return switch (score) {
            case 3 -> new BigDecimal("0.84");
            case 2 -> new BigDecimal("0.70");
            case 1 -> new BigDecimal("0.52");
            default -> new BigDecimal("0.30");
        };
    }
}


