            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            int limit
    );
}


DocumentChunkVectorRepositoryImpl.java


package com.myllm.financeai.document.repository;

import com.myllm.financeai.rag.dto.RetrievedChunk;
import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import jakarta.persistence.Query;
import java.sql.Timestamp;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Repository;

@Repository
public class DocumentChunkVectorRepositoryImpl implements DocumentChunkVectorRepository {

    @PersistenceContext
    private EntityManager em;

    @Override
    @SuppressWarnings("unchecked")
    public List<RetrievedChunk> searchSimilarChunks(
            String queryEmbedding,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            int limit
    ) {
        StringBuilder sql = new StringBuilder("""
            select
                dc.id as chunk_id,
                d.id as document_id,
                dc.chunk_text,
                dc.chunk_index,
                d.title as document_title,
                d.source_name,
                d.published_at,
                1 - (dc.embedding <=> cast(:embedding as vector)) as similarity
            from document_chunks dc
            join documents d on d.id = dc.document_id
            where dc.embedding is not null
        """);

        if (publishedFrom != null) {
            sql.append(" and d.published_at >= :publishedFrom ");
        }
        if (publishedTo != null) {
            sql.append(" and d.published_at <= :publishedTo ");
        }

        sql.append("""
            order by dc.embedding <=> cast(:embedding as vector)
            limit :limit
        """);

        Query query = em.createNativeQuery(sql.toString());
        query.setParameter("embedding", queryEmbedding);

        if (publishedFrom != null) {
            query.setParameter("publishedFrom", Timestamp.valueOf(publishedFrom));
        }
        if (publishedTo != null) {
            query.setParameter("publishedTo", Timestamp.valueOf(publishedTo));
        }

        query.setParameter("limit", limit);

        List<Object[]> rows = query.getResultList();
        List<RetrievedChunk> result = new ArrayList<>();

        for (Object[] row : rows) {
            result.add(new RetrievedChunk(
                    (UUID) row[0],
                    (UUID) row[1],
                    (String) row[2],
                    ((Number) row[3]).intValue(),
                    (String) row[4],
                    (String) row[5],
                    row[6] != null ? ((Timestamp) row[6]).toLocalDateTime() : null,
                    ((Number) row[7]).doubleValue()
            ));
        }

        return result;
    }
}


중요 포인트는 이거다.


query embedding을 '[0.1, 0.2, ...]' 문자열 형태로 넘겨서 cast

cosine distance <=> 사용

similarity는 1 - distance



