package com.myllm.financeai.ai.service;

import java.util.List;
import java.util.stream.Collectors;
import lombok.RequiredArgsConstructor;
import org.springframework.ai.embedding.EmbeddingModel;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class EmbeddingService {

    private final EmbeddingModel embeddingModel;

    public List<Double> embed(String text) {
        return embeddingModel.embed(text);
    }

    public String embedAsPgVectorLiteral(String text) {
        List<Double> vector = embed(text);
        return toPgVectorLiteral(vector);
    }

    public String toPgVectorLiteral(List<Double> vector) {
        return "[" + vector.stream()
                .map(v -> Double.toString(v))
                .collect(Collectors.joining(","))
                + "]";
    }
}



8. chunk 생성 서비스


