DocumentChunkService.java


package com.myllm.financeai.document.service;

import com.myllm.financeai.document.entity.Document;
import com.myllm.financeai.document.entity.DocumentChunk;
import com.myllm.financeai.document.repository.DocumentChunkRepository;
import java.util.ArrayList;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional
public class DocumentChunkService {

    private final DocumentChunkRepository documentChunkRepository;

    public List<DocumentChunk> createChunks(Document document) {
        documentChunkRepository.deleteByDocumentId(document.getId());

        List<String> chunks = splitText(document.getCleanedText(), 900, 150);
        List<DocumentChunk> saved = new ArrayList<>();

        for (int i = 0; i < chunks.size(); i++) {
            DocumentChunk chunk = DocumentChunk.builder()
                    .document(document)
                    .chunkIndex(i)
                    .chunkText(chunks.get(i))
                    .tokenCount(estimateTokenCount(chunks.get(i)))
                    .embedding(null)
                    .metadataJson("{}")
                    .build();
            saved.add(documentChunkRepository.save(chunk));
        }

        return saved;
    }

    private List<String> splitText(String text, int chunkSize, int overlap) {
        List<String> result = new ArrayList<>();
        if (text == null || text.isBlank()) {
            return result;
        }

        int start = 0;
        int length = text.length();

        while (start < length) {
            int end = Math.min(start + chunkSize, length);
            result.add(text.substring(start, end));

            if (end == length) {
                break;
            }
            start = end - overlap;
            if (start < 0) {
                start = 0;
            }
        }

        return result;
    }

    private int estimateTokenCount(String text) {
        if (text == null) return 0;
        return Math.max(1, text.length() / 3);
    }
}


1차는 이 정도면 충분하다.
나중에 진짜로 토큰 기반 chunking으로 바꾸면 됨.



