package com.myllm.financeai.document.service;

import com.myllm.financeai.ai.service.EmbeddingService;
import com.myllm.financeai.document.entity.Document;
import com.myllm.financeai.document.entity.DocumentChunk;
import com.myllm.financeai.document.repository.DocumentChunkRepository;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional
public class DocumentIndexingService {

    private final DocumentChunkService documentChunkService;
    private final DocumentChunkRepository documentChunkRepository;
    private final EmbeddingService embeddingService;

    public void indexDocument(Document document) {
        List<DocumentChunk> chunks = documentChunkService.createChunks(document);

        for (DocumentChunk chunk : chunks) {
            String embedding = embeddingService.embedAsPgVectorLiteral(chunk.getChunkText());

            DocumentChunk updated = DocumentChunk.builder()
                    .document(chunk.getDocument())
                    .chunkIndex(chunk.getChunkIndex())
                    .chunkText(chunk.getChunkText())
                    .tokenCount(chunk.getTokenCount())
                    .embedding(embedding)
                    .metadataJson(chunk.getMetadataJson())
                    .build();

            // 주의: 이 방식은 새 엔티티처럼 보일 수 있으니 아래처럼 setter/update 메서드가 더 좋음
        }
    }
}


여기서 중요한 문제가 하나 있다.
현재 DocumentChunk 엔티티가 불변 스타일 + update 메서드 없음이라 embedding 갱신이 불편하다.


