AnswerComposerService.java


package com.myllm.financeai.analysis.service;

import com.myllm.financeai.ai.dto.FinanceAnalysisAiResult;
import com.myllm.financeai.analysis.dto.AnalysisMaterial;
import com.myllm.financeai.analysis.dto.AnalysisAnswerResponse;
import com.myllm.financeai.analysis.dto.AnalysisResponse;
import com.myllm.financeai.analysis.dto.CitationResponse;
import com.myllm.financeai.analysis.dto.RelatedEntityResponse;
import com.myllm.financeai.analysis.dto.ToolTraceResponse;
import com.myllm.financeai.rag.dto.RetrievedChunk;
import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.springframework.stereotype.Service;

@Service
public class AnswerComposerService {

    public AnalysisResponse composeWithAi(
            String intent,
            AnalysisMaterial material,
            FinanceAnalysisAiResult aiResult
    ) {
        List<CitationResponse> citations = buildCitations(material.retrievedChunks());
        List<RelatedEntityResponse> relatedEntities = buildRelatedEntities(material);

        return new AnalysisResponse(
                null,
                intent,
                new AnalysisAnswerResponse(
                        aiResult.summary(),
                        aiResult.fullText(),
                        estimateConfidence(material),
                        aiResult.uncertaintyNote()
                ),
                citations,
                relatedEntities,
                buildToolTrace(material)
        );
    }

    public AnalysisResponse withSessionId(AnalysisResponse response, UUID sessionId) {
        return new AnalysisResponse(
                sessionId,
                response.queryIntent(),
                response.answer(),
                response.citations(),
                response.relatedEntities(),
                response.toolTrace()
        );
    }

    private List<CitationResponse> buildCitations(List<RetrievedChunk> chunks) {
        Map<UUID, CitationResponse> deduped = new LinkedHashMap<>();

        for (RetrievedChunk chunk : chunks) {
            deduped.putIfAbsent(
                    chunk.documentId(),
                    new CitationResponse(
                            chunk.documentId(),
                            chunk.documentTitle(),
                            chunk.sourceName(),
                            chunk.publishedAt(),
                            null
                    )
            );
        }

        return new ArrayList<>(deduped.values());
    }

    private List<RelatedEntityResponse> buildRelatedEntities(AnalysisMaterial material) {
        List<RelatedEntityResponse> relatedEntities = new ArrayList<>();

        if (material.priceSummary() != null) {
            relatedEntities.add(new RelatedEntityResponse("TICKER", material.priceSummary().ticker()));
            relatedEntities.add(new RelatedEntityResponse("MARKET", material.priceSummary().market()));
        }

        if (material.financialSummary() != null) {
            relatedEntities.add(new RelatedEntityResponse("FINANCIAL_PERIOD",
                    material.financialSummary().latestFiscalYear()
                            + (material.financialSummary().latestFiscalQuarter() != null
                            ? "Q" + material.financialSummary().latestFiscalQuarter()
                            : "")
            ));
        }

        return relatedEntities;
    }

    private List<ToolTraceResponse> buildToolTrace(AnalysisMaterial material) {
        return List.of(
                new ToolTraceResponse(
                        "ragRetrieval",
                        material.retrievedChunks() != null && !material.retrievedChunks().isEmpty()
                                ? "SUCCESS"
                                : "EMPTY"
                ),
                new ToolTraceResponse(
                        "priceSummary",
                        material.priceSummary() != null ? "SUCCESS" : "SKIPPED"
                ),
                new ToolTraceResponse(
                        "financialSummary",
                        material.financialSummary() != null ? "SUCCESS" : "SKIPPED"
                ),
                new ToolTraceResponse("springAiChatClient", "SUCCESS")
        );
    }

    private BigDecimal estimateConfidence(AnalysisMaterial material) {
        int score = 0;

        if (material.retrievedChunks() != null && !material.retrievedChunks().isEmpty()) score++;
        if (material.priceSummary() != null) score++;
        if (material.financialSummary() != null) score++;

        return switch (score) {
            case 3 -> new BigDecimal("0.86");
            case 2 -> new BigDecimal("0.71");
            case 1 -> new BigDecimal("0.53");
            default -> new BigDecimal("0.30");
        };
    }
}


핵심 변화:


material.documents() 제거

material.retrievedChunks() 기반으로 citation 생성

같은 문서에서 여러 chunk가 검색돼도 citation은 1개만 남김



