5. keyword 검색 repository 추가


이제 document_chunks.chunk_text와 documents.title 기준으로 lexical 검색을 해야 한다.


DocumentChunkKeywordRepository.java


package com.myllm.financeai.document.repository;

import com.myllm.financeai.rag.dto.RetrievedChunk;
import java.time.LocalDateTime;
import java.util.List;

public interface DocumentChunkKeywordRepository {
    List<RetrievedChunk> searchKeywordChunks(
            String query,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            int limit
    );
}



DocumentChunkKeywordRepositoryImpl.java


package com.myllm.financeai.document.repository;

import com.myllm.financeai.rag.dto.RetrievedChunk;
import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import jakarta.persistence.Query;
import java.sql.Timestamp;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Repository;

@Repository
public class DocumentChunkKeywordRepositoryImpl implements DocumentChunkKeywordRepository {

    @PersistenceContext
    private EntityManager em;

    @Override
    @SuppressWarnings("unchecked")
    public List<RetrievedChunk> searchKeywordChunks(
            String queryText,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            int limit
    ) {
        StringBuilder sql = new StringBuilder("""
            select
                dc.id as chunk_id,
                d.id as document_id,
                dc.chunk_text,
                dc.chunk_index,
                d.title as document_title,
                d.source_name,
                d.published_at,
                ts_rank_cd(
                    setweight(to_tsvector('simple', coalesce(d.title, '')), 'A') ||
                    setweight(to_tsvector('simple', coalesce(dc.chunk_text, '')), 'B'),
                    plainto_tsquery('simple', :queryText)
                ) as keyword_score
            from document_chunks dc
            join documents d on d.id = dc.document_id
            where (
                setweight(to_tsvector('simple', coalesce(d.title, '')), 'A') ||
                setweight(to_tsvector('simple', coalesce(dc.chunk_text, '')), 'B')
            ) @@ plainto_tsquery('simple', :queryText)
        """);

        if (publishedFrom != null) {
            sql.append(" and d.published_at >= :publishedFrom ");
        }
        if (publishedTo != null) {
            sql.append(" and d.published_at <= :publishedTo ");
        }

        sql.append("""
            order by keyword_score desc, d.published_at desc nulls last
            limit :limit
        """);

        Query query = em.createNativeQuery(sql.toString());
        query.setParameter("queryText", queryText);

        if (publishedFrom != null) {
            query.setParameter("publishedFrom", Timestamp.valueOf(publishedFrom));
        }
        if (publishedTo != null) {
            query.setParameter("publishedTo", Timestamp.valueOf(publishedTo));
        }

        query.setParameter("limit", limit);

        List<Object[]> rows = query.getResultList();
        List<RetrievedChunk> result = new ArrayList<>();

        for (Object[] row : rows) {
            result.add(new RetrievedChunk(
                    (UUID) row[0],
                    (UUID) row[1],
                    (String) row[2],
                    ((Number) row[3]).intValue(),
                    (String) row[4],
                    (String) row[5],
                    row[6] != null ? ((Timestamp) row[6]).toLocalDateTime() : null,
                    ((Number) row[7]).doubleValue()
            ));
        }

        return result;
    }
}


여기서 RetrievedChunk.similarity 필드를 keyword score로 재사용하고 있다.
즉 vector 검색에서는 similarity, keyword 검색에서는 keyword rank가 들어간다.



