7. HybridRetrievalService 구현


이게 핵심이다.


HybridRetrievalService.java


package com.myllm.financeai.rag.service;

import com.myllm.financeai.ai.service.EmbeddingService;
import com.myllm.financeai.document.repository.DocumentChunkKeywordRepository;
import com.myllm.financeai.document.repository.DocumentChunkVectorRepository;
import com.myllm.financeai.rag.dto.HybridRetrievedChunk;
import com.myllm.financeai.rag.dto.RetrievedChunk;
import java.time.LocalDateTime;
import java.util.*;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class HybridRetrievalService {

    private final EmbeddingService embeddingService;
    private final DocumentChunkVectorRepository documentChunkVectorRepository;
    private final DocumentChunkKeywordRepository documentChunkKeywordRepository;

    public List<HybridRetrievedChunk> retrieve(
            String query,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            int limit
    ) {
        String queryEmbedding = embeddingService.embedAsPgVectorLiteral(query);

        List<RetrievedChunk> vectorResults = documentChunkVectorRepository.searchSimilarChunks(
                queryEmbedding,
                publishedFrom,
                publishedTo,
                limit * 2
        );

        List<RetrievedChunk> keywordResults = documentChunkKeywordRepository.searchKeywordChunks(
                query,
                publishedFrom,
                publishedTo,
                limit * 2
        );

        return mergeAndRank(vectorResults, keywordResults, limit);
    }

    private List<HybridRetrievedChunk> mergeAndRank(
            List<RetrievedChunk> vectorResults,
            List<RetrievedChunk> keywordResults,
            int limit
    ) {
        Map<UUID, ChunkScoreAccumulator> map = new LinkedHashMap<>();

        double maxVector = vectorResults.stream()
                .mapToDouble(RetrievedChunk::similarity)
                .max()
                .orElse(1.0);

        double maxKeyword = keywordResults.stream()
                .mapToDouble(RetrievedChunk::similarity)
                .max()
                .orElse(1.0);

        for (RetrievedChunk chunk : vectorResults) {
            map.computeIfAbsent(chunk.chunkId(), id -> new ChunkScoreAccumulator(chunk))
                    .setVectorScore(normalize(chunk.similarity(), maxVector));
        }

        for (RetrievedChunk chunk : keywordResults) {
            map.computeIfAbsent(chunk.chunkId(), id -> new ChunkScoreAccumulator(chunk))
                    .setKeywordScore(normalize(chunk.similarity(), maxKeyword));
        }

        List<HybridRetrievedChunk> merged = map.values().stream()
                .map(acc -> {
                    double finalScore = (acc.vectorScore * 0.6) + (acc.keywordScore * 0.4);
                    return new HybridRetrievedChunk(
                            acc.chunk.chunkId(),
                            acc.chunk.documentId(),
                            acc.chunk.chunkText(),
                            acc.chunk.chunkIndex(),
                            acc.chunk.documentTitle(),
                            acc.chunk.sourceName(),
                            acc.chunk.publishedAt(),
                            round(acc.vectorScore),
                            round(acc.keywordScore),
                            round(finalScore)
                    );
                })
                .sorted(Comparator.comparingDouble(HybridRetrievedChunk::finalScore).reversed())
                .limit(limit)
                .toList();

        return merged;
    }

    private double normalize(double score, double max) {
        if (max <= 0) return 0.0;
        double normalized = score / max;
        if (normalized < 0) return 0.0;
        if (normalized > 1) return 1.0;
        return normalized;
    }

    private double round(double value) {
        return Math.round(value * 10000.0) / 10000.0;
    }

    private static class ChunkScoreAccumulator {
        private final RetrievedChunk chunk;
        private double vectorScore;
        private double keywordScore;

        private ChunkScoreAccumulator(RetrievedChunk chunk) {
            this.chunk = chunk;
        }

        public void setVectorScore(double vectorScore) {
            this.vectorScore = vectorScore;
        }

        public void setKeywordScore(double keywordScore) {
            this.keywordScore = keywordScore;
        }
    }
}



8. 왜 0.6 / 0.4냐


초기 추천값은 이렇다.


vector 0.6

keyword 0.4


이유는:


자연어 질문 이해는 vector가 강함

금융 고유명사/핵심 용어는 keyword가 강함


이건 나중에 조정 가능하다.


금융 도메인에서는 오히려 아래처럼 바꿀 수도 있다.


보통: 0.6 / 0.4

숫자·공시·용어 질문이 많음: 0.5 / 0.5

자연어 질의가 많음: 0.7 / 0.3


지금은 0.6 / 0.4 추천.



