4. NeighborChunkExpansionService 추가


이게 핵심이다.


NeighborChunkExpansionService.java


package com.myllm.financeai.rag.service;

import com.myllm.financeai.document.entity.DocumentChunk;
import com.myllm.financeai.document.repository.DocumentChunkRepository;
import com.myllm.financeai.rag.dto.ExpandedRetrievedChunk;
import com.myllm.financeai.rag.dto.HybridRetrievedChunk;
import java.util.ArrayList;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class NeighborChunkExpansionService {

    private final DocumentChunkRepository documentChunkRepository;

    public List<ExpandedRetrievedChunk> expand(List<HybridRetrievedChunk> chunks) {
        List<ExpandedRetrievedChunk> result = new ArrayList<>();

        for (HybridRetrievedChunk chunk : chunks) {
            int start = Math.max(0, chunk.chunkIndex() - 1);
            int end = chunk.chunkIndex() + 1;

            List<DocumentChunk> neighbors =
                    documentChunkRepository.findByDocumentIdAndChunkIndexBetweenOrderByChunkIndexAsc(
                            chunk.documentId(),
                            start,
                            end
                    );

            List<Integer> indexes = neighbors.stream()
                    .map(DocumentChunk::getChunkIndex)
                    .toList();

            String expandedText = neighbors.stream()
                    .map(DocumentChunk::getChunkText)
                    .reduce((a, b) -> a + "\n\n" + b)
                    .orElse(chunk.chunkText());

            result.add(new ExpandedRetrievedChunk(
                    chunk.chunkId(),
                    chunk.documentId(),
                    chunk.documentTitle(),
                    chunk.sourceName(),
                    chunk.publishedAt(),
                    chunk.chunkIndex(),
                    chunk.vectorScore(),
                    chunk.keywordScore(),
                    chunk.finalScore(),
                    indexes,
                    expandedText
            ));
        }

        return result;
    }
}


이건 기본형이다.
즉 앞 1개 + 현재 + 뒤 1개.



