        List<ExpandedRetrievedChunk> expanded = neighborChunkExpansionService.expand(retrieved);

        PriceSummary priceSummary = null;
        FinancialSummary financialSummary = null;

        if (ticker != null && !ticker.isBlank() && market != null && !market.isBlank()) {
            if (timeFrom != null && timeTo != null) {
                priceSummary = priceService.summarizePriceHistory(
                        ticker,
                        market,
                        timeFrom.toLocalDate(),
                        timeTo.toLocalDate()
                );
            }

            financialSummary = financialMetricService.summarizeLatestFinancials(ticker, market);
        }

        return new AnalysisMaterial(
                expanded,
                priceSummary,
                financialSummary
        );
    }
}



