4. ContextMergeService 추가


ContextMergeService.java


package com.myllm.financeai.rag.service;

import com.myllm.financeai.rag.dto.ExpandedRetrievedChunk;
import com.myllm.financeai.rag.dto.MergedExpandedContext;
import java.util.*;
import org.springframework.stereotype.Service;

@Service
public class ContextMergeService {

    public List<MergedExpandedContext> merge(List<ExpandedRetrievedChunk> expandedChunks) {
        if (expandedChunks == null || expandedChunks.isEmpty()) {
            return List.of();
        }

        Map<UUID, List<ExpandedRetrievedChunk>> byDocument = expandedChunks.stream()
                .collect(java.util.stream.Collectors.groupingBy(
                        ExpandedRetrievedChunk::documentId,
                        LinkedHashMap::new,
                        java.util.stream.Collectors.toList()
                ));

        List<MergedExpandedContext> mergedResults = new ArrayList<>();

        for (Map.Entry<UUID, List<ExpandedRetrievedChunk>> entry : byDocument.entrySet()) {
            List<ExpandedRetrievedChunk> chunks = entry.getValue().stream()
                    .sorted(Comparator.comparingInt(ExpandedRetrievedChunk::centerChunkIndex))
                    .toList();

            List<List<ExpandedRetrievedChunk>> groups = groupAdjacent(chunks);

            for (List<ExpandedRetrievedChunk> group : groups) {
                mergedResults.add(toMergedContext(group));
            }
        }

        return mergedResults;
    }

    private List<List<ExpandedRetrievedChunk>> groupAdjacent(List<ExpandedRetrievedChunk> chunks) {
        List<List<ExpandedRetrievedChunk>> groups = new ArrayList<>();
        List<ExpandedRetrievedChunk> current = new ArrayList<>();

        for (ExpandedRetrievedChunk chunk : chunks) {
            if (current.isEmpty()) {
                current.add(chunk);
                continue;
            }

            ExpandedRetrievedChunk prev = current.get(current.size() - 1);

            if (isOverlappingOrAdjacent(prev, chunk)) {
                current.add(chunk);
            } else {
                groups.add(new ArrayList<>(current));
                current.clear();
                current.add(chunk);
            }
        }

        if (!current.isEmpty()) {
            groups.add(current);
        }

        return groups;
    }

    private boolean isOverlappingOrAdjacent(ExpandedRetrievedChunk a, ExpandedRetrievedChunk b) {
        int aMin = Collections.min(a.includedChunkIndexes());
        int aMax = Collections.max(a.includedChunkIndexes());
        int bMin = Collections.min(b.includedChunkIndexes());
        int bMax = Collections.max(b.includedChunkIndexes());

        return bMin <= aMax + 1;
    }

    private MergedExpandedContext toMergedContext(List<ExpandedRetrievedChunk> group) {
        ExpandedRetrievedChunk first = group.get(0);

        SortedSet<Integer> allIndexes = new TreeSet<>();
        List<UUID> centerChunkIds = new ArrayList<>();
        List<Integer> hitChunkIndexes = new ArrayList<>();

        double maxVector = 0.0;
        double maxKeyword = 0.0;
        double maxHybrid = 0.0;

        for (ExpandedRetrievedChunk chunk : group) {
            allIndexes.addAll(chunk.includedChunkIndexes());
            centerChunkIds.add(chunk.centerChunkId());
            hitChunkIndexes.add(chunk.centerChunkIndex());

            maxVector = Math.max(maxVector, chunk.vectorScore());
            maxKeyword = Math.max(maxKeyword, chunk.keywordScore());
            maxHybrid = Math.max(maxHybrid, chunk.finalScore());
        }

        String expandedText = group.stream()
                .map(ExpandedRetrievedChunk::expandedText)
                .distinct()
                .reduce((a, b) -> a + "\n\n" + b)
                .orElse("");

        return new MergedExpandedContext(
                first.documentId(),
                first.documentTitle(),
                first.sourceName(),
                first.publishedAt(),
                centerChunkIds,
                hitChunkIndexes,
                new ArrayList<>(allIndexes),
                round(maxVector),
                round(maxKeyword),
                round(maxHybrid),
                expandedText
        );
    }

    private double round(double value) {
        return Math.round(value * 10000.0) / 10000.0;
    }
}



5. 문제 하나: expandedText를 그냥 distinct concat 하면 중복이 남음


위 코드는 빠른 버전이다.
하지만 expandedText를 단순 문자열 distinct로 합치면 문장 일부가 중복될 수 있다.


더 좋은 방식은 includedChunkIndexes를 기준으로 실제 chunk를 다시 조회해서 정순으로 합치는 것이다.


그래서 실무적으로는 이 버전이 더 좋다.



6. 더 정확한 merge 버전


ContextMergeService에서 DocumentChunkRepository를 주입받아 실제 chunk를 다시 읽는다.


개선 버전 ContextMergeService.java


package com.myllm.financeai.rag.service;

import com.myllm.financeai.document.entity.DocumentChunk;
import com.myllm.financeai.document.repository.DocumentChunkRepository;
import com.myllm.financeai.rag.dto.ExpandedRetrievedChunk;
import com.myllm.financeai.rag.dto.MergedExpandedContext;
import java.util.*;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class ContextMergeService {

    private final DocumentChunkRepository documentChunkRepository;

    public List<MergedExpandedContext> merge(List<ExpandedRetrievedChunk> expandedChunks) {
        if (expandedChunks == null || expandedChunks.isEmpty()) {
            return List.of();
        }

        Map<UUID, List<ExpandedRetrievedChunk>> byDocument = expandedChunks.stream()
                .collect(java.util.stream.Collectors.groupingBy(
                        ExpandedRetrievedChunk::documentId,
                        LinkedHashMap::new,
                        java.util.stream.Collectors.toList()
                ));

        List<MergedExpandedContext> mergedResults = new ArrayList<>();

        for (Map.Entry<UUID, List<ExpandedRetrievedChunk>> entry : byDocument.entrySet()) {
            List<ExpandedRetrievedChunk> chunks = entry.getValue().stream()
                    .sorted(Comparator.comparingInt(ExpandedRetrievedChunk::centerChunkIndex))
                    .toList();

            List<List<ExpandedRetrievedChunk>> groups = groupAdjacent(chunks);

            for (List<ExpandedRetrievedChunk> group : groups) {
                mergedResults.add(toMergedContext(group));
            }
        }

        return mergedResults;
    }

    private List<List<ExpandedRetrievedChunk>> groupAdjacent(List<ExpandedRetrievedChunk> chunks) {
        List<List<ExpandedRetrievedChunk>> groups = new ArrayList<>();
        List<ExpandedRetrievedChunk> current = new ArrayList<>();

        for (ExpandedRetrievedChunk chunk : chunks) {
            if (current.isEmpty()) {
                current.add(chunk);
                continue;
            }

            ExpandedRetrievedChunk prev = current.get(current.size() - 1);

            if (isOverlappingOrAdjacent(prev, chunk)) {
                current.add(chunk);
            } else {
                groups.add(new ArrayList<>(current));
                current.clear();
                current.add(chunk);
            }
        }

        if (!current.isEmpty()) {
            groups.add(current);
        }

        return groups;
    }

    private boolean isOverlappingOrAdjacent(ExpandedRetrievedChunk a, ExpandedRetrievedChunk b) {
        int aMin = Collections.min(a.includedChunkIndexes());
        int aMax = Collections.max(a.includedChunkIndexes());
        int bMin = Collections.min(b.includedChunkIndexes());
        int bMax = Collections.max(b.includedChunkIndexes());

        return bMin <= aMax + 1;
    }

    private MergedExpandedContext toMergedContext(List<ExpandedRetrievedChunk> group) {
        ExpandedRetrievedChunk first = group.get(0);

        SortedSet<Integer> allIndexes = new TreeSet<>();
        List<UUID> centerChunkIds = new ArrayList<>();
        List<Integer> hitChunkIndexes = new ArrayList<>();

        double maxVector = 0.0;
        double maxKeyword = 0.0;
        double maxHybrid = 0.0;

        for (ExpandedRetrievedChunk chunk : group) {
            allIndexes.addAll(chunk.includedChunkIndexes());
            centerChunkIds.add(chunk.centerChunkId());
            hitChunkIndexes.add(chunk.centerChunkIndex());

            maxVector = Math.max(maxVector, chunk.vectorScore());
            maxKeyword = Math.max(maxKeyword, chunk.keywordScore());
            maxHybrid = Math.max(maxHybrid, chunk.finalScore());
        }

        int minIndex = allIndexes.first();
        int maxIndex = allIndexes.last();

        List<DocumentChunk> actualChunks =
                documentChunkRepository.findByDocumentIdAndChunkIndexBetweenOrderByChunkIndexAsc(
                        first.documentId(),
                        minIndex,
                        maxIndex
                );

        String expandedText = actualChunks.stream()
                .map(DocumentChunk::getChunkText)
                .reduce((a, b) -> a + "\n\n" + b)
                .orElse("");

        return new MergedExpandedContext(
                first.documentId(),
                first.documentTitle(),
                first.sourceName(),
                first.publishedAt(),
                centerChunkIds,
                hitChunkIndexes,
                new ArrayList<>(allIndexes),
                round(maxVector),
                round(maxKeyword),
                round(maxHybrid),
                expandedText
        );
    }

    private double round(double value) {
        return Math.round(value * 10000.0) / 10000.0;
    }
}


이 버전이 더 좋다.
중복 문맥 제거가 제대로 된다.



7. 이제 reranker 붙이기


여기서 reranker는 merged context 단위에 적용해야 한다.


즉 hybrid retrieval 결과에 바로 붙이는 게 아니라:


hybrid hits → neighbor expansion → adjacent merge → rerank


이 순서가 맞다.



8. reranker 방식 선택


reranker는 세 가지 길이 있다.


1) 규칙 기반 경량 reranker


질문과 context의 키워드 overlap

publishedAt recency bonus

hybridScore 재가중


장점:


바로 구현 가능

비용 0

빠름


단점:


