10. LightweightRerankerService 추가


LightweightRerankerService.java


package com.myllm.financeai.rag.service;

import com.myllm.financeai.rag.dto.MergedExpandedContext;
import com.myllm.financeai.rag.dto.RerankedContext;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;
import org.springframework.stereotype.Service;

@Service
public class LightweightRerankerService {

    public List<RerankedContext> rerank(String query, List<MergedExpandedContext> contexts, int limit) {
        Set<String> queryTerms = tokenize(query);

        return contexts.stream()
                .map(ctx -> {
                    double keywordOverlap = computeKeywordOverlap(queryTerms, ctx.expandedText());
                    double recencyBoost = computeRecencyBoost(ctx.publishedAt());

                    double rerankScore =
                            (ctx.hybridScore() * 0.6)
                            + (keywordOverlap * 0.3)
                            + (recencyBoost * 0.1);

                    return new RerankedContext(
                            ctx.documentId(),
                            ctx.documentTitle(),
                            ctx.sourceName(),
                            ctx.publishedAt(),
                            ctx.centerChunkIds(),
                            ctx.hitChunkIndexes(),
                            ctx.includedChunkIndexes(),
                            ctx.maxVectorScore(),
                            ctx.maxKeywordScore(),
                            ctx.hybridScore(),
                            round(rerankScore),
                            ctx.expandedText()
                    );
                })
                .sorted(Comparator.comparingDouble(RerankedContext::rerankScore).reversed())
                .limit(limit)
                .toList();
    }

    private Set<String> tokenize(String text) {
        if (text == null || text.isBlank()) return Set.of();

        return Arrays.stream(text.toLowerCase().split("\\s+"))
                .map(String::trim)
                .filter(s -> !s.isBlank())
                .collect(Collectors.toSet());
    }

    private double computeKeywordOverlap(Set<String> queryTerms, String text) {
        if (queryTerms.isEmpty() || text == null || text.isBlank()) return 0.0;

        String lower = text.toLowerCase();
        long matched = queryTerms.stream()
                .filter(lower::contains)
                .count();

        return Math.min(1.0, (double) matched / queryTerms.size());
    }

    private double computeRecencyBoost(LocalDateTime publishedAt) {
        if (publishedAt == null) return 0.0;

        long days = ChronoUnit.DAYS.between(publishedAt, LocalDateTime.now());

        if (days <= 3) return 1.0;
        if (days <= 7) return 0.8;
        if (days <= 30) return 0.5;
        if (days <= 90) return 0.2;
        return 0.0;
    }

    private double round(double value) {
        return Math.round(value * 10000.0) / 10000.0;
    }
}


