import com.myllm.financeai.rag.dto.RerankedContext;


private List<CitationResponse> buildCitations(List<RerankedContext> chunks) {
    Map<UUID, CitationResponse> deduped = new LinkedHashMap<>();

    for (RerankedContext chunk : chunks) {
        deduped.putIfAbsent(
                chunk.documentId(),
                new CitationResponse(
                        chunk.documentId(),
                        chunk.documentTitle(),
                        chunk.sourceName(),
                        chunk.publishedAt(),
                        null
                )
        );
    }

    return new ArrayList<>(deduped.values());
}


