public class DocumentChunkKeywordRepositoryImpl implements DocumentChunkKeywordRepository {

    @PersistenceContext
    private EntityManager em;

    @Override
    @SuppressWarnings("unchecked")
    public List<RetrievedChunk> searchKeywordChunks(
            String queryText,
            RetrievalFilter filter,
            int limit
    ) {
        StringBuilder sql = new StringBuilder("""
            select
                dc.id as chunk_id,
                d.id as document_id,
                dc.chunk_text,
                dc.chunk_index,
                d.title as document_title,
                d.source_name,
                d.published_at,
                ts_rank_cd(
                    setweight(to_tsvector('simple', coalesce(d.title, '')), 'A') ||
                    setweight(to_tsvector('simple', coalesce(dc.chunk_text, '')), 'B'),
                    plainto_tsquery('simple', :queryText)
                ) as keyword_score
            from document_chunks dc
            join documents d on d.id = dc.document_id
            where (
