package com.myllm.financeai.rag.service;

import com.myllm.financeai.document.enums.SourceType;
import com.myllm.financeai.rag.dto.*;
import java.time.LocalDateTime;
import java.util.*;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class FallbackHybridRetrievalService {

    private final HybridRetrievalService hybridRetrievalService;

    public FallbackHybridRetrievalResult retrieveWithFallback(
            String query,
            String ticker,
            String market,
            LocalDateTime publishedFrom,
            LocalDateTime publishedTo,
            SourceTypePlan plan,
            int perSourceLimit
    ) {
        Map<UUID, HybridRetrievedChunk> merged = new LinkedHashMap<>();
        List<SourceFallbackTrace> fallbackTraces = new ArrayList<>();

        for (SourceType sourceType : plan.priorityOrder()) {
            RetrievalFilter filter = new RetrievalFilter(
                    ticker,
                    market,
                    sourceType,
                    publishedFrom,
                    publishedTo
            );

            List<HybridRetrievedChunk> results = hybridRetrievalService.retrieve(
                    query,
                    filter,
                    perSourceLimit
            );

            boolean used = false;
            for (HybridRetrievedChunk chunk : results) {
                if (!merged.containsKey(chunk.chunkId())) {
                    merged.put(chunk.chunkId(), chunk);
                    used = true;
                }
            }

            fallbackTraces.add(new SourceFallbackTrace(
                    sourceType.name(),
                    results.size(),
                    used
            ));

            if (merged.size() >= plan.minimumResults()) {
                break;
            }
        }

        List<HybridRetrievedChunk> finalResults = merged.values().stream()
                .sorted(Comparator.comparingDouble(HybridRetrievedChunk::finalScore).reversed())
                .limit(plan.minimumResults())
                .toList();

        return new FallbackHybridRetrievalResult(finalResults, fallbackTraces);
    }
}



