package com.myllm.financeai.analysis.service;

import com.myllm.financeai.analysis.dto.AnalysisMaterial;
import com.myllm.financeai.analysis.dto.PriceSummary;
import com.myllm.financeai.analysis.enums.QueryIntentType;
import com.myllm.financeai.market.dto.FinancialSummary;
import com.myllm.financeai.market.service.FinancialMetricService;
import com.myllm.financeai.market.service.PriceService;
import com.myllm.financeai.rag.dto.*;
import com.myllm.financeai.rag.service.ContextMergeService;
import com.myllm.financeai.rag.service.FallbackHybridRetrievalService;
import com.myllm.financeai.rag.service.LightweightRerankerService;
import com.myllm.financeai.rag.service.NeighborChunkExpansionService;
import java.time.LocalDateTime;
import java.util.List;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@RequiredArgsConstructor
@Transactional(readOnly = true)
public class AnalysisPipelineService {

    private final SourceTypePlanningService sourceTypePlanningService;
    private final FallbackHybridRetrievalService fallbackHybridRetrievalService;
    private final NeighborChunkExpansionService neighborChunkExpansionService;
    private final ContextMergeService contextMergeService;
    private final LightweightRerankerService lightweightRerankerService;
    private final PriceService priceService;
    private final FinancialMetricService financialMetricService;

    public RetrievalResult loadMaterial(
            String query,
            QueryIntentType intent,
            String ticker,
            String market,
            LocalDateTime timeFrom,
            LocalDateTime timeTo
    ) {
        SourceTypePlan sourceTypePlan = sourceTypePlanningService.buildPlan(intent);

        FallbackHybridRetrievalResult fallbackResult =
                fallbackHybridRetrievalService.retrieveWithFallback(
                        query,
                        ticker,
                        market,
                        timeFrom,
                        timeTo,
                        sourceTypePlan,
                        6
                );

        List<HybridRetrievedChunk> retrieved = fallbackResult.retrievedChunks();
        List<ExpandedRetrievedChunk> expanded = neighborChunkExpansionService.expand(retrieved);
        List<MergedExpandedContext> merged = contextMergeService.merge(expanded);
        List<RerankedContext> reranked = lightweightRerankerService.rerank(query, merged, 5);

        PriceSummary priceSummary = null;
        FinancialSummary financialSummary = null;

        if (ticker != null && !ticker.isBlank() && market != null && !market.isBlank()) {
            if (timeFrom != null && timeTo != null) {
                priceSummary = priceService.summarizePriceHistory(
                        ticker,
                        market,
                        timeFrom.toLocalDate(),
                        timeTo.toLocalDate()
                );
            }

            financialSummary = financialMetricService.summarizeLatestFinancials(ticker, market);
        }

        AnalysisMaterial material = new AnalysisMaterial(
                reranked,
                priceSummary,
                financialSummary
        );

        RetrievalTrace trace = new RetrievalTrace(
                fallbackResult.sourceFallbacks(),
                toHybridTrace(retrieved),
                toExpandedTrace(expanded),
                toMergedTrace(merged),
                toRerankedTrace(reranked)
        );

        return new RetrievalResult(material, trace);
    }

    private List<HybridRetrievedChunkTrace> toHybridTrace(List<HybridRetrievedChunk> chunks) {
        return chunks.stream()
                .map(chunk -> new HybridRetrievedChunkTrace(
                        chunk.chunkId(),
                        chunk.documentId(),
                        chunk.documentTitle(),
                        chunk.chunkIndex(),
                        chunk.vectorScore(),
                        chunk.keywordScore(),
                        chunk.finalScore()
                ))
                .toList();
    }

    private List<ExpandedChunkTrace> toExpandedTrace(List<ExpandedRetrievedChunk> chunks) {
        return chunks.stream()
                .map(chunk -> new ExpandedChunkTrace(
                        chunk.centerChunkId(),
                        chunk.documentId(),
                        chunk.documentTitle(),
                        chunk.centerChunkIndex(),
                        chunk.includedChunkIndexes()
                ))
                .toList();
    }

    private List<MergedContextTrace> toMergedTrace(List<MergedExpandedContext> contexts) {
        return contexts.stream()
                .map(ctx -> new MergedContextTrace(
                        ctx.documentId(),
                        ctx.documentTitle(),
                        ctx.centerChunkIds(),
                        ctx.hitChunkIndexes(),
                        ctx.includedChunkIndexes(),
                        ctx.hybridScore()
                ))
                .toList();
    }

    private List<RerankedContextTrace> toRerankedTrace(List<RerankedContext> contexts) {
        return contexts.stream()
                .map(ctx -> new RerankedContextTrace(
                        ctx.documentId(),
                        ctx.documentTitle(),
                        ctx.includedChunkIndexes(),
                        ctx.hybridScore(),
                        ctx.rerankScore()
                ))
                .toList();
    }
}



