        .session(savedSession)
        .finalAnswer(response.answer().fullText())
        .summary(response.answer().summary())
        .confidenceScore(response.answer().confidenceScore())
        .uncertaintyNote(response.answer().uncertaintyNote())
        .citedDocumentIds(toJsonSafe(
                response.citations().stream()
                        .map(CitationResponse::documentId)
                        .toList()
        ))
        .citedChunkIds("[]")
        .toolTraceJson(toJsonSafe(retrievalTrace))
        .modelName("spring-ai-mistral")
        .promptVersion("v1")
        .build();


즉 이제 tool_trace_json은 단순 tool list가 아니라 retrieval pipeline 전체 trace를 저장한다.



