4. API 함수


src/lib/api.ts


import type { AnalysisSessionDetail } from "../types/analysis";
import type { RetrievalTrace } from "../types/retrieval-trace";

const API_BASE = "/api/v1";

export async function fetchSessionDetail(sessionId: string, token: string): Promise<AnalysisSessionDetail> {
  const res = await fetch(`${API_BASE}/analysis/sessions/${sessionId}`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!res.ok) {
    throw new Error("세션 상세 조회에 실패했습니다.");
  }

  const json = await res.json();
  return json.data;
}

export async function fetchRetrievalTrace(sessionId: string, token: string): Promise<RetrievalTrace> {
  const res = await fetch(`${API_BASE}/analysis/sessions/${sessionId}/retrieval-trace`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!res.ok) {
    throw new Error("retrieval trace 조회에 실패했습니다.");
  }

  const json = await res.json();
  return json.data;
}



5. 공통 포맷 함수


src/lib/format.ts


export function formatDateTime(value?: string | null): string {
  if (!value) return "-";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString("ko-KR");
}

export function formatScore(value?: number | null): string {
  if (value == null) return "-";
  return value.toFixed(4);
}

export function truncateText(text: string, max = 180): string {
  if (!text) return "";
  return text.length <= max ? text : `${text.slice(0, max)}...`;
}



