  const token = "TOKEN_FROM_AUTH_STORE";

  useEffect(() => {
    async function load() {
      try {
        const result = await fetchSessionDetail(sessionId, token);
        setData(result);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, [sessionId, token]);

  if (loading) {
    return <div className="p-8 text-sm text-slate-500">불러오는 중...</div>;
  }

  if (!data) {
    return <div className="p-8 text-sm text-red-500">세션을 불러오지 못했습니다.</div>;
  }

  return (
    <div className="mx-auto max-w-6xl space-y-6 p-6">
      <header className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="text-xs text-slate-500">{formatDateTime(data.createdAt)}</div>
        <h1 className="mt-2 text-2xl font-bold text-slate-900">{data.title}</h1>
        <p className="mt-3 text-sm text-slate-700">{data.queryText}</p>
      </header>

      <section className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="flex flex-wrap items-center gap-3">
          <span className="rounded-full bg-slate-100 px-3 py-1 text-xs text-slate-700">
            {data.queryIntent}
          </span>
          <span className="rounded-full bg-blue-50 px-3 py-1 text-xs text-blue-700">
            confidence {data.result.confidenceScore.toFixed(2)}
          </span>
        </div>

        <p className="mt-4 text-base font-semibold text-slate-900">{data.result.summary}</p>
      </section>

      <div className="rounded-2xl border border-slate-200 bg-white shadow-sm">
        <div className="flex border-b border-slate-100">
          <TabButton active={tab === "answer"} onClick={() => setTab("answer")}>
            Answer
          </TabButton>
          <TabButton active={tab === "citations"} onClick={() => setTab("citations")}>
            Citations
          </TabButton>
          <TabButton active={tab === "trace"} onClick={() => setTab("trace")}>
            Retrieval Trace
          </TabButton>
        </div>

        <div className="p-6">
          {tab === "answer" && (
            <div className="space-y-4">
              <div className="whitespace-pre-wrap text-sm leading-7 text-slate-800">
                {data.result.fullText}
              </div>
              <div className="rounded-xl bg-amber-50 p-4 text-sm text-amber-800">
                {data.result.uncertaintyNote}
              </div>
            </div>
          )}

          {tab === "citations" && (
            <div className="space-y-3">
              {data.citations.map((citation) => (
                <div key={citation.documentId} className="rounded-xl border border-slate-200 p-4">
                  <div className="text-sm font-semibold text-slate-900">{citation.title}</div>
                  <div className="mt-1 text-xs text-slate-500">
                    {citation.sourceName} / {formatDateTime(citation.publishedAt)}
                  </div>
                </div>
              ))}
            </div>
          )}

          {tab === "trace" && <RetrievalTraceTab trace={data.retrievalTrace} />}
        </div>
      </div>
    </div>
  );
}

function TabButton({
  active,
  onClick,
  children,
}: {
  active: boolean;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      className={`px-5 py-3 text-sm font-medium ${
        active
          ? "border-b-2 border-slate-900 text-slate-900"
          : "text-slate-500 hover:text-slate-800"
      }`}
    >
      {children}
    </button>
  );
}



