src/lib/api.ts


import { USE_MOCK } from "./env";
import type { AnalysisSessionDetail } from "../types/analysis";
import type { RetrievalTrace } from "../types/retrieval-trace";
import { mockSessionDetail } from "../mocks/session-detail.mock";
import { mockRetrievalTrace } from "../mocks/retrieval-trace.mock";

const API_BASE = "/api/v1";

function sleep(ms = 300) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function fetchSessionDetail(
  sessionId: string,
  token: string
): Promise<AnalysisSessionDetail> {
  if (USE_MOCK) {
    await sleep();
    return {
      ...mockSessionDetail,
      sessionId,
      retrievalTrace: mockRetrievalTrace,
    };
  }

  const res = await fetch(`${API_BASE}/analysis/sessions/${sessionId}`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!res.ok) {
    throw new Error("세션 상세 조회에 실패했습니다.");
  }

  const json = await res.json();
  return json.data;
}

export async function fetchRetrievalTrace(
  sessionId: string,
  token: string
): Promise<RetrievalTrace> {
  if (USE_MOCK) {
    await sleep();
    return mockRetrievalTrace;
  }

  const res = await fetch(`${API_BASE}/analysis/sessions/${sessionId}/retrieval-trace`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!res.ok) {
    throw new Error("retrieval trace 조회에 실패했습니다.");
  }

  const json = await res.json();
  return json.data;
}



5. useSessionDetail hook


UI에서 직접 fetch 하지 말고 hook으로 감싸자.


src/hooks/useSessionDetail.ts


import { useCallback, useEffect, useState } from "react";
import { fetchSessionDetail } from "../lib/api";
import type { AnalysisSessionDetail } from "../types/analysis";

type UseSessionDetailResult = {
  data: AnalysisSessionDetail | null;
  isLoading: boolean;
  error: string | null;
  refetch: () => Promise<void>;
};

export function useSessionDetail(sessionId: string | undefined, token: string | undefined): UseSessionDetailResult {
  const [data, setData] = useState<AnalysisSessionDetail | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    if (!sessionId || !token) return;

    setIsLoading(true);
    setError(null);

    try {
      const result = await fetchSessionDetail(sessionId, token);
      setData(result);
    } catch (err) {
      const message = err instanceof Error ? err.message : "알 수 없는 오류가 발생했습니다.";
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }, [sessionId, token]);

  useEffect(() => {
    void load();
  }, [load]);

  return {
    data,
    isLoading,
    error,
    refetch: load,
  };
}



6. useRetrievalTrace hook


trace를 별도로 다시 가져오고 싶을 때 쓸 수 있게 만든다.


src/hooks/useRetrievalTrace.ts


import { useCallback, useEffect, useState } from "react";
import { fetchRetrievalTrace } from "../lib/api";
import type { RetrievalTrace } from "../types/retrieval-trace";

type UseRetrievalTraceResult = {
  data: RetrievalTrace | null;
  isLoading: boolean;
  error: string | null;
  refetch: () => Promise<void>;
};

export function useRetrievalTrace(
  sessionId: string | undefined,
  token: string | undefined,
  enabled = true
): UseRetrievalTraceResult {
  const [data, setData] = useState<RetrievalTrace | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const load = useCallback(async () => {
    if (!enabled || !sessionId || !token) return;

    setIsLoading(true);
    setError(null);

    try {
      const result = await fetchRetrievalTrace(sessionId, token);
      setData(result);
    } catch (err) {
      const message = err instanceof Error ? err.message : "알 수 없는 오류가 발생했습니다.";
      setError(message);
    } finally {
      setIsLoading(false);
    }
  }, [enabled, sessionId, token]);

  useEffect(() => {
    void load();
  }, [load]);

  return {
    data,
    isLoading,
    error,
    refetch: load,
  };
}



7. page 전용 조합 hook


세션 상세와 retrieval trace를 같이 다루는 페이지라면 page hook 하나 더 두는 게 편하다.


src/hooks/useSessionDetailPage.ts


import { useMemo, useState } from "react";
import { useSessionDetail } from "./useSessionDetail";
import { useRetrievalTrace } from "./useRetrievalTrace";

export function useSessionDetailPage(sessionId: string | undefined, token: string | undefined) {
  const [traceMode, setTraceMode] = useState<"embedded" | "separate">("embedded");

  const sessionQuery = useSessionDetail(sessionId, token);
  const traceQuery = useRetrievalTrace(
    sessionId,
    token,
    traceMode === "separate"
  );

  const retrievalTrace = useMemo(() => {
    if (traceMode === "embedded") {
      return sessionQuery.data?.retrievalTrace ?? null;
    }
    return traceQuery.data;
  }, [traceMode, sessionQuery.data, traceQuery.data]);

  const isLoading = sessionQuery.isLoading || (traceMode === "separate" && traceQuery.isLoading);

  return {
    session: sessionQuery.data,
    retrievalTrace,
    isLoading,
    error: sessionQuery.error || traceQuery.error,
    refetchAll: async () => {
      await sessionQuery.refetch();
      if (traceMode === "separate") {
        await traceQuery.refetch();
      }
    },
    traceMode,
    setTraceMode,
  };
}


이 hook이 좋은 이유는:


백엔드가 retrievalTrace를 세션 상세에 포함해주면 embedded 모드

나중에 trace를 별도 API로 빼도 separate 모드

화면 코드를 덜 바꾸게 해줌



