4. API


mock과 real 전환 쉽게.


api.ts


import { mockSessions } from "./mock";
import { Session } from "./types";

const USE_MOCK = true;

export async function fetchSessions(): Promise<Session[]> {
  if (USE_MOCK) {
    return new Promise((r) => setTimeout(() => r(mockSessions), 200));
  }

  const res = await fetch("/api/v1/sessions");
  const json = await res.json();
  return json.data;
}

export async function runAnalysis(query: string): Promise<Session> {
  if (USE_MOCK) {
    return new Promise((r) => setTimeout(() => r(mockSessions[0]), 200));
  }

  const res = await fetch("/api/v1/analysis/query", {
    method: "POST",
    body: JSON.stringify({ query }),
  });

  const json = await res.json();
  return json.data;
}



