              <th>Query</th>
            </tr>
          </thead>
          <tbody>
            {sessions.map((s) => (
              <tr key={s.sessionId} onClick={() => setSelected(s)}>
                <td>{s.sessionId}</td>
                <td>{s.queryText}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {selected && (
