            String intent,
            String ticker,
            String market,
            String from,
            String to
    ) {
        QueryIntentType queryIntent = QueryIntentType.valueOf(intent);
        LocalDateTime fromDateTime = parseDateTime(from);
        LocalDateTime toDateTime = parseDateTime(to);

        SourceTypePlan sourceTypePlan = sourceTypePlanningService.buildPlan(queryIntent);

        FallbackHybridRetrievalResult fallbackResult =
                fallbackHybridRetrievalService.retrieveWithFallback(
                        query,
                        ticker,
                        market,
                        fromDateTime,
                        toDateTime,
                        sourceTypePlan,
                        6
                );

        List<ExpandedRetrievedChunk> expanded =
                neighborChunkExpansionService.expand(fallbackResult.retrievedChunks());

        List<MergedExpandedContext> merged = contextMergeService.merge(expanded);

        List<RerankedContext> reranked =
                lightweightRerankerService.rerank(query, merged, 5);

        List<ContextSearchToolResult.ContextItem> items = reranked.stream()
                .map(item -> new ContextSearchToolResult.ContextItem(
                        item.documentTitle(),
                        item.sourceName(),
                        item.publishedAt() == null ? null : item.publishedAt().toString(),
                        item.rerankScore(),
                        item.expandedText()
                ))
                .toList();

        return new ContextSearchToolResult(query, items.size(), items);
    }

    public PriceSummaryToolResult getPriceSummary(
            String ticker,
            String market,
            String from,
            String to
    ) {
        if (ticker == null || ticker.isBlank() || market == null || market.isBlank()) {
            return null;
        }

        var summary = priceService.summarizePriceHistory(
                ticker,
                market,
                LocalDate.parse(from),
                LocalDate.parse(to)
        );

        if (summary == null) {
            return null;
        }

        return new PriceSummaryToolResult(
                summary.ticker(),
                summary.market(),
                summary.fromDate().toString(),
                summary.toDate().toString(),
                String.valueOf(summary.firstClosePrice()),
                String.valueOf(summary.lastClosePrice()),
                String.valueOf(summary.absoluteChange()),
                String.valueOf(summary.percentChange()),
                String.valueOf(summary.averageVolume())
        );
    }

    public FinancialSummaryToolResult getFinancialSummary(
            String ticker,
            String market
    ) {
        if (ticker == null || ticker.isBlank() || market == null || market.isBlank()) {
            return null;
        }

        FinancialSummary summary = financialMetricService.summarizeLatestFinancials(ticker, market);

        if (summary == null) {
            return null;
        }

        return new FinancialSummaryToolResult(
                summary.ticker(),
                summary.market(),
                String.valueOf(summary.latestFiscalYear()),
                summary.latestFiscalQuarter() == null ? null : String.valueOf(summary.latestFiscalQuarter()),
                summary.periodType(),
                String.valueOf(summary.revenue()),
                String.valueOf(summary.operatingIncome()),
                String.valueOf(summary.netIncome()),
                String.valueOf(summary.eps()),
                String.valueOf(summary.operatingMargin()),
                String.valueOf(summary.netMargin()),
                String.valueOf(summary.debtRatio())
        );
    }

    private LocalDateTime parseDateTime(String value) {
        if (value == null || value.isBlank()) return null;
        return LocalDateTime.parse(value);
    }
}



8. ToolCallingAnalysisService 만들기


이 서비스가 “질문을 받고, 툴을 쓸 수 있는 LLM” 호출을 담당한다.


여기서 중요한 건 질문을 LLM에 바로 던지는 게 아니라, 툴 사용 규칙을 강하게 주는 것이다.


ToolCallingAnalysisService.java


package com.myllm.financeai.ai.service;

import com.myllm.financeai.ai.dto.FinanceAnalysisAiResult;
import lombok.RequiredArgsConstructor;
import org.springframework.ai.chat.client.ChatClient;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class ToolCallingAnalysisService {

    private final ChatClient.Builder chatClientBuilder;

    public FinanceAnalysisAiResult analyzeWithTools(
            String query,
            String intent,
            String ticker,
            String market,
            String from,
            String to
    ) {
        ChatClient chatClient = chatClientBuilder.build();

        String systemPrompt = """
                너는 금융 분석 보조 AI다.
                너는 필요할 때 도구를 호출해서 데이터를 수집한 뒤 답해야 한다.
                추측보다 도구 호출을 우선하라.

                도구 사용 원칙:
                1. 문서 근거가 필요하면 searchRelevantContexts를 호출하라.
                2. 가격 흐름이 필요하면 getPriceSummary를 호출하라.
                3. 재무 상태가 필요하면 getFinancialSummary를 호출하라.
                4. 모든 질문에 무조건 모든 도구를 호출할 필요는 없다.
                5. 도구 결과가 없으면 없다고 명시하라.

                출력 형식:
                [SUMMARY]
                ...
                [FULL_TEXT]
                ...
                [UNCERTAINTY]
                ...
                """;

        String userPrompt = """
                질문: %s
                분석유형: %s
                ticker: %s
                market: %s
                from: %s
                to: %s

                위 질문에 대해 필요한 도구를 호출해 분석하라.
                """.formatted(
                query,
                intent,
                ticker,
                market,
                from,
                to
        );

        String raw = chatClient.prompt()
                .system(systemPrompt)
                .user(userPrompt)
                .call()
                .content();

        return parse(raw);
    }

    private FinanceAnalysisAiResult parse(String raw) {
        String summary = extractSection(raw, "[SUMMARY]", "[FULL_TEXT]");
        String fullText = extractSection(raw, "[FULL_TEXT]", "[UNCERTAINTY]");
        String uncertainty = extractSection(raw, "[UNCERTAINTY]", null);

        return new FinanceAnalysisAiResult(
                emptyToFallback(summary, "요약을 생성하지 못했습니다."),
                emptyToFallback(fullText, raw),
                emptyToFallback(uncertainty, "현재 데이터 범위에 기반한 제한적 분석입니다.")
        );
    }

    private String extractSection(String raw, String start, String end) {
        int startIdx = raw.indexOf(start);
        if (startIdx < 0) return "";

        int contentStart = startIdx + start.length();
        int endIdx = end == null ? raw.length() : raw.indexOf(end, contentStart);

        if (endIdx < 0) endIdx = raw.length();
        return raw.substring(contentStart, endIdx).trim();
    }

    private String emptyToFallback(String value, String fallback) {
        return (value == null || value.isBlank()) ? fallback : value;
    }
}



9. 실제 tool binding


여기서 방식이 두 갈래다.


간단한 방식


LLM이 tool “개념적으로” 쓰게 프롬프트만 구성
→ 너가 백엔드에서 미리 호출


진짜 tool calling 방식


Spring AI tool binding 사용
→ LLM이 실제로 tool 호출


너는 “진행”이 목적이니까 진짜 tool calling으로 가는 게 맞다.
다만 구현은 모델/버전에 따라 약간 달라질 수 있어서, 구조적으로는 이렇게 잡는 게 안전하다.


Spring AI에서 @Tool 또는 function callback 계열로 연결할 수 있는데,
여기서는 도구 메서드를 별도 bean에 두고 등록하는 방향이 가장 자연스럽다.


즉 AnalysisToolService 메서드를 tool로 노출.



10. 추천 실제 연결 구조


AiConfig에서 ChatClient를 만들 때 tool bean 등록하는 방식으로 간다.


개념적으로는 이런 느낌이다.


@Bean
ChatClient financeChatClient(ChatClient.Builder builder, AnalysisToolService toolService) {
    return builder
            .defaultTools(toolService)
            .build();
}


그리고 AnalysisToolService의 도구 메서드는 tool metadata가 붙어야 한다.


예를 들어:


@Tool(description = "질문과 관련된 문맥을 검색한다")
public ContextSearchToolResult searchRelevantContexts(...) { ... }


@Tool(description = "주가 요약 정보를 조회한다")
public PriceSummaryToolResult getPriceSummary(...) { ... }


@Tool(description = "최신 재무 요약 정보를 조회한다")
public FinancialSummaryToolResult getFinancialSummary(...) { ... }


정확한 annotation/package는 네가 쓰는 Spring AI 버전에 맞춰 확인해 붙이면 되고,
구조상으로는 이 방향이 맞다.



11. AnalysisToolService를 tool-friendly 하게 수정


즉 메서드명, 파라미터명, 설명을 LLM이 이해하기 쉽게 해야 한다.


추천은:


파라미터를 너무 많게 하지 말기

문자열 위주로 통일

null 가능성 명시

결과를 간단한 DTO로 반환


현재 작성한 형태가 거의 적절하다.



12. AnalysisService에서 무엇을 바꿀까


현재는 AnalysisPipelineService가 미리 다 준비하고 FinanceAnalysisAiService에 넣고 있었다.
이제 선택지는 2개다.


방식 A


기존 파이프라인 유지 + tool calling은 별도 실험 기능


방식 B


기존 파이프라인 일부를 tool calling으로 대체


추천은 A로 시작이다.


즉:


현재 deterministic pipeline은 유지

별도 tool calling mode 추가

나중에 비교 가능


왜냐면 tool calling은 좋아도,
디버깅성과 예측 가능성은 기존 파이프라인이 더 높다.


즉 AnalysisService를 이렇게 확장 추천.



13. AnalysisService 모드 분기


개념


mode = PIPELINE

mode = TOOL_CALLING


예를 들어 request에 optional field 추가:


AnalysisQueryRequest.java 추가 필드


String analysisMode


예:


"PIPELINE"

"TOOL_CALLING"


없으면 기본 PIPELINE.



AnalysisService.java 수정 예시


private final ToolCallingAnalysisService toolCallingAnalysisService;


그리고 analyze() 안에서:


String mode = request.analysisMode() == null ? "PIPELINE" : request.analysisMode();

AnalysisResponse response;

if ("TOOL_CALLING".equalsIgnoreCase(mode)) {
    FinanceAnalysisAiResult aiResult = toolCallingAnalysisService.analyzeWithTools(
            request.query(),
            intent.name(),
            request.ticker(),
            request.market(),
            request.timeFrom() == null ? null : request.timeFrom().toString(),
            request.timeTo() == null ? null : request.timeTo().toString()
    );

    response = answerComposerService.composeToolCallingResult(intent.name(), aiResult);
} else {
    RetrievalResult retrievalResult = analysisPipelineService.loadMaterial(
            request.query(),
            intent,
            request.ticker(),
            request.market(),
            request.timeFrom(),
            request.timeTo()
    );

    FinanceAnalysisAiResult aiResult = financeAnalysisAiService.generate(
            request.query(),
            intent.name(),
            retrievalResult.material()
    );

    response = answerComposerService.composeWithAi(
            intent.name(),
            retrievalResult.material(),
            aiResult
    );

    UUID sessionId = analysisSessionService.save(
            userId,
            request,
            intent,
            response,
            retrievalResult.trace()
    );

    return answerComposerService.withSessionId(response, sessionId);
}


tool calling 모드는 trace가 deterministic retrieval trace와 다르므로
초기엔 간단한 tool trace만 저장해도 된다.



