@Transactional
public AnalysisCompareResponse compare(UUID userId, AnalysisQueryRequest request) {
    AnalysisQueryRequest pipelineRequest = new AnalysisQueryRequest(
            request.query(),
            request.market(),
            request.ticker(),
            request.timeFrom(),
            request.timeTo(),
            request.useWebSearch(),
            request.saveResult(),
            "PIPELINE"
    );

    AnalysisQueryRequest toolCallingRequest = new AnalysisQueryRequest(
            request.query(),
            request.market(),
            request.ticker(),
            request.timeFrom(),
            request.timeTo(),
            request.useWebSearch(),
            request.saveResult(),
            "TOOL_CALLING"
    );

    AnalysisResponse pipelineResult = analyze(userId, pipelineRequest);
    AnalysisResponse toolCallingResult = analyze(userId, toolCallingRequest);

    return new AnalysisCompareResponse(pipelineResult, toolCallingResult);
}



