import type { AnalysisCompareResponse } from "./types";
import { mockCompareResult } from "./mock";

const USE_MOCK = true;

export async function compareAnalysis(payload: {
  query: string;
  ticker: string;
  market: string;
  timeFrom: string;
  timeTo: string;
}): Promise<AnalysisCompareResponse> {
  if (USE_MOCK) {
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockCompareResult), 300);
    });
  }

  const token = "TOKEN_FROM_AUTH_STORE";

  const res = await fetch("/api/v1/analysis/compare", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${token}`
    },
    body: JSON.stringify({
      query: payload.query,
      ticker: payload.ticker,
      market: payload.market,
      timeFrom: payload.timeFrom,
      timeTo: payload.timeTo,
      saveResult: true
    })
  });

  if (!res.ok) {
    throw new Error("비교 분석 요청에 실패했습니다.");
  }

  const json = await res.json();
  return json.data;
}



