  toolName: string;
  status: string;
};

export type Citation = {
  documentId: string;
  title: string;
  sourceName: string;
  publishedAt: string | null;
  url: string | null;
};

export type SourceFallback = {
  sourceType: string;
  retrievedCount: number;
  used: boolean;
};

export type HybridResult = {
  chunkId: string;
  documentId: string;
  documentTitle: string;
  chunkIndex: number;
  vectorScore: number;
  keywordScore: number;
  finalScore: number;
};

export type ExpandedResult = {
  centerChunkId: string;
  documentId: string;
  documentTitle: string;
  centerChunkIndex: number;
  includedChunkIndexes: number[];
};

export type MergedResult = {
  documentId: string;
  documentTitle: string;
  centerChunkIds: string[];
  hitChunkIndexes: number[];
  includedChunkIndexes: number[];
  hybridScore: number;
};

export type RerankedResult = {
  documentId: string;
  documentTitle: string;
  includedChunkIndexes: number[];
  hybridScore: number;
  rerankScore: number;
  expandedText: string;
};

export type RetrievalTrace = {
  sourceFallbacks: SourceFallback[];
  hybridResults: HybridResult[];
  expandedResults: ExpandedResult[];
  mergedResults: MergedResult[];
  rerankedResults: RerankedResult[];
};

export type AnalysisResultView = {
  sessionId: string;
  queryIntent: string;
  answer: {
    summary: string;
    fullText: string;
    confidenceScore: number;
    uncertaintyNote: string;
  };
  citations: Citation[];
  toolTrace: ToolTrace[];
  retrievalTrace?: RetrievalTrace;
};

export type AnalysisCompareResponse = {
  pipeline: AnalysisResultView;
  toolCalling: AnalysisResultView;
};



