import { useEffect, useState } from "react";
import { compareAnalysis, fetchRecentSessions } from "./api";
import type { AnalysisCompareResponse, AnalysisResultView, SessionListItem } from "./types";
import "./style.css";

export default function App() {
  const [query, setQuery] = useState("SK하이닉스 최근 투자포인트 설명해줘");
  const [ticker, setTicker] = useState("000660");
  const [market, setMarket] = useState("KR");
  const [timeFrom, setTimeFrom] = useState("2026-03-01T00:00:00");
  const [timeTo, setTimeTo] = useState("2026-03-13T23:59:59");

  const [result, setResult] = useState<AnalysisCompareResponse | null>(null);
  const [recentSessions, setRecentSessions] = useState<SessionListItem[]>([]);
  const [selectedSessionId, setSelectedSessionId] = useState("");

  const [loading, setLoading] = useState(false);
  const [listLoading, setListLoading] = useState(false);
  const [error, setError] = useState("");
  const [popupText, setPopupText] = useState("");
  const [popupTitle, setPopupTitle] = useState("");

  useEffect(() => {
    loadRecentSessions();
  }, []);

  async function loadRecentSessions() {
    setListLoading(true);
    try {
      const data = await fetchRecentSessions();
      setRecentSessions(data);
    } catch (e) {
      console.error(e);
    } finally {
      setListLoading(false);
    }
  }

  async function handleRun() {
    setLoading(true);
    setError("");

    try {
      const data = await compareAnalysis({
        query,
        ticker,
        market,
        timeFrom,
        timeTo
      });
      setResult(data);
      await loadRecentSessions();
    } catch (e) {
      setError(e instanceof Error ? e.message : "오류가 발생했습니다.");
    } finally {
      setLoading(false);
    }
  }

  async function handleSelectSession(item: SessionListItem) {
    setSelectedSessionId(item.sessionId);
    setQuery(item.queryText);

    setLoading(true);
    setError("");

    try {
      const data = await compareAnalysis({
        query: item.queryText,
        ticker,
        market,
        timeFrom,
        timeTo
      });
      setResult(data);
    } catch (e) {
      setError(e instanceof Error ? e.message : "세션 조회 중 오류가 발생했습니다.");
    } finally {
      setLoading(false);
    }
  }

  function openPopup(title: string, text: string) {
    setPopupTitle(title);
    setPopupText(text);
  }

  function closePopup() {
    setPopupTitle("");
    setPopupText("");
  }

  return (
