api.ts


import type { AnalysisCompareResponse, AnalysisResultView, SessionListItem } from "./types";
import { mockCompareResult, mockRecentSessions } from "./mock";

const USE_MOCK = true;

export async function runAnalysis(payload: {
  query: string;
  ticker: string;
  market: string;
  timeFrom: string;
  timeTo: string;
  analysisMode: string;
}): Promise<AnalysisCompareResponse> {
  if (USE_MOCK) {
    return new Promise((resolve) => {
      setTimeout(() => {
        if (payload.analysisMode === "PIPELINE") {
          resolve({
            pipeline: mockCompareResult.pipeline,
            toolCalling: null as unknown as AnalysisResultView,
          });
          return;
        }

        if (payload.analysisMode === "TOOL_CALLING") {
          resolve({
            pipeline: null as unknown as AnalysisResultView,
            toolCalling: mockCompareResult.toolCalling,
          });
          return;
        }

        resolve(mockCompareResult);
      }, 300);
    });
  }

  const token = "TOKEN_FROM_AUTH_STORE";

  if (payload.analysisMode === "BOTH") {
    const res = await fetch("/api/v1/analysis/compare", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`
      },
      body: JSON.stringify({
        query: payload.query,
        ticker: payload.ticker,
        market: payload.market,
        timeFrom: payload.timeFrom,
        timeTo: payload.timeTo,
        saveResult: true
      })
    });

    if (!res.ok) {
      throw new Error("비교 분석 요청에 실패했습니다.");
    }

    const json = await res.json();
    return json.data;
  }

  const res = await fetch("/api/v1/analysis/query", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${token}`
    },
    body: JSON.stringify({
      query: payload.query,
      ticker: payload.ticker,
      market: payload.market,
      timeFrom: payload.timeFrom,
      timeTo: payload.timeTo,
      saveResult: true,
      analysisMode: payload.analysisMode
    })
  });

  if (!res.ok) {
    throw new Error("분석 요청에 실패했습니다.");
  }

  const json = await res.json();

  if (payload.analysisMode === "PIPELINE") {
    return {
      pipeline: json.data,
      toolCalling: null as unknown as AnalysisResultView,
    };
  }

  return {
    pipeline: null as unknown as AnalysisResultView,
    toolCalling: json.data,
  };
}

export async function fetchRecentSessions(): Promise<SessionListItem[]> {
  if (USE_MOCK) {
    return new Promise((resolve) => {
      setTimeout(() => resolve(mockRecentSessions), 150);
    });
  }

  const token = "TOKEN_FROM_AUTH_STORE";

  const res = await fetch("/api/v1/analysis/sessions?page=0&size=20", {
    headers: {
      Authorization: `Bearer ${token}`
    }
  });

  if (!res.ok) {
    throw new Error("최근 세션 목록 조회에 실패했습니다.");
  }

  const json = await res.json();
  return json.data.items;
}



