3. diff summary 함수 추가


App.tsx 위쪽이나 아래쪽에 함수 하나 추가하자.


function buildDiffSummary(result: AnalysisCompareResponse): string[] {
  const messages: string[] = [];

  if (!result.pipeline || !result.toolCalling) {
    return messages;
  }

  const pipelineConfidence = result.pipeline.answer.confidenceScore;
  const toolConfidence = result.toolCalling.answer.confidenceScore;

  if (pipelineConfidence > toolConfidence) {
    messages.push(`PIPELINE confidence가 더 높음 (${pipelineConfidence} > ${toolConfidence})`);
  } else if (toolConfidence > pipelineConfidence) {
    messages.push(`TOOL_CALLING confidence가 더 높음 (${toolConfidence} > ${pipelineConfidence})`);
  } else {
    messages.push(`두 모드의 confidence가 동일함 (${pipelineConfidence})`);
  }

  const pipelineToolCount = result.pipeline.toolTrace.length;
  const toolToolCount = result.toolCalling.toolTrace.length;

  if (pipelineToolCount > toolToolCount) {
    messages.push(`PIPELINE이 더 많은 tool trace를 가짐 (${pipelineToolCount}개)`);
  } else if (toolToolCount > pipelineToolCount) {
    messages.push(`TOOL_CALLING이 더 많은 tool trace를 가짐 (${toolToolCount}개)`);
  } else {
    messages.push(`두 모드의 tool trace 개수가 같음 (${pipelineToolCount}개)`);
  }

  const pipelineCitationCount = result.pipeline.citations.length;
  const toolCitationCount = result.toolCalling.citations.length;

  if (pipelineCitationCount > toolCitationCount) {
    messages.push(`PIPELINE이 더 많은 citation을 포함함 (${pipelineCitationCount}개)`);
  } else if (toolCitationCount > pipelineCitationCount) {
    messages.push(`TOOL_CALLING이 더 많은 citation을 포함함 (${toolCitationCount}개)`);
  } else {
    messages.push(`두 모드의 citation 개수가 같음 (${pipelineCitationCount}개)`);
  }

  const pipelineHasTrace = !!result.pipeline.retrievalTrace;
  const toolHasTrace = !!result.toolCalling.retrievalTrace;

  if (pipelineHasTrace && !toolHasTrace) {
    messages.push("PIPELINE만 retrieval trace를 포함함");
  } else if (!pipelineHasTrace && toolHasTrace) {
    messages.push("TOOL_CALLING만 retrieval trace를 포함함");
  } else if (pipelineHasTrace && toolHasTrace) {
    messages.push("두 모드 모두 retrieval trace를 포함함");
  } else {
    messages.push("두 모드 모두 retrieval trace가 없음");
  }

  return messages;
}



