2. 정렬 함수 수정


기존 sortSessionsByConfidence()를 일반화하자.


function sortSessions(items: SessionListItem[], sortBy: string): SessionListItem[] {
  const copied = [...items];

  if (sortBy === "createdAt") {
    return copied.sort(
      (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }

  return copied.sort((a, b) => b.confidence - a.confidence);
}



3. 필터 함수 추가


function filterSessions(
  items: SessionListItem[],
  modeFilter: string,
  minConfidence: string
): SessionListItem[] {
  const min = Number(minConfidence || "0");

  return items.filter((item) => {
    const modeMatch = modeFilter === "ALL" ? true : item.mode === modeFilter;
    const confidenceMatch = item.confidence >= min;
    return modeMatch && confidenceMatch;
  });
}



