레거시 운영 화면에서는 이게 더 실용적이다.



3. 정렬된 목록에서 선택된 row를 맨 위로 올리는 함수 추가


이제 핵심이다.
정렬/필터 이후에 선택된 세션만 맨 위로 재배치하면 된다.


function pinSelectedSessionToTop(
  items: SessionListItem[],
  selectedSessionId: string
): SessionListItem[] {
  if (!selectedSessionId) {
    return items;
  }

  const selected = items.find((item) => item.sessionId === selectedSessionId);

  if (!selected) {
    return items;
  }

  const others = items.filter((item) => item.sessionId !== selectedSessionId);
  return [selected, ...others];
}



