@Transactional(readOnly = true)
public PageResponse<AnalysisSessionSummaryResponse> getSessions(UUID userId, Pageable pageable) {
    Page<AnalysisSession> sessions = analysisSessionRepository.findByUserIdOrderByCreatedAtDesc(userId, pageable);

    Page<AnalysisSessionSummaryResponse> mapped = sessions.map(session -> {
        AnalysisResult result = analysisResultRepository.findBySessionId(session.getId()).orElse(null);

        return new AnalysisSessionSummaryResponse(
                session.getId(),
                session.getTitle(),
                session.getQueryText(),
                session.getQueryIntent().name(),
                session.getAnalysisMode(),
                result != null ? result.getConfidenceScore() : BigDecimal.ZERO,
                session.getCreatedAt()
