@Transactional(readOnly = true)
public AnalysisSessionDetailResponse getSessionDetail(UUID userId, UUID sessionId) {
    AnalysisSession session = analysisSessionRepository.findById(sessionId)
            .orElseThrow(() -> new BusinessException(ErrorCode.INVALID_INPUT));

    if (!session.getUser().getId().equals(userId)) {
        throw new BusinessException(ErrorCode.FORBIDDEN);
    }

    AnalysisResult result = analysisResultRepository.findBySessionId(sessionId)
            .orElseThrow(() -> new BusinessException(ErrorCode.INVALID_INPUT));

    RetrievalTraceResponse retrievalTrace = readRetrievalTrace(result.getToolTraceJson());

    List<ToolTraceResponse> toolTrace = List.of(); // 필요하면 기존 방식 유지

    return new AnalysisSessionDetailResponse(
            session.getId(),
            session.getTitle(),
            session.getQueryText(),
            session.getQueryIntent().name(),
            new AnalysisAnswerResponse(
                    result.getSummary(),
                    result.getFinalAnswer(),
                    result.getConfidenceScore(),
                    result.getUncertaintyNote()
            ),
            List.of(),
            toolTrace,
            retrievalTrace,
            session.getCreatedAt()
    );
}



